        [PART.HEADING]: PART.HEADING,
        [PART.ADD_BTN]: PART.ADD_BTN,
        [PART.HANDLE]: PART.HANDLE,
        [PART.LIST_ROW]: PART.LIST_ROW,
        [PART.LIST_MARKER]: PART.LIST_MARKER,
        [PART.LIST_CONTENT]: PART.LIST_CONTENT,
        [PART.TODO_ROW]: PART.TODO_ROW,
        [PART.TODO_CHECK]: PART.TODO_CHECK,
