/**
 * @fileoverview BlockEditor events — centralised event binding for keyboard,
 *               toolbar clicks, drag-drop reordering, input/paste,
 *               selection-based format bar, and slash command menu.
 *
 * Every exported function receives a thin `ctx` context object that proxies
 * access to the class's private fields (see index.js `#ctx()`).
 *
 * @module module/BlockEditor/events
 */

import razyui from '../../index.js';
import {
    isCaretAtStart,
    isCaretAtEnd,
    tryRemoveLeadingLineBreakIfAtStart,
    toggleInlineCode,
    insertInlineLink,
} from './helpers.js';
import { buildBlockMenu } from './view.js';

// ═══════════════════════════════════════════════
// Global listeners (attached once during init)
// ═══════════════════════════════════════════════

/**
 * Attach document-level listeners for selection change and slash-menu dismiss.
 * @param {Object} ctx — editor context
 */
export function initGlobalListeners(ctx) {
    const opts = ctx.signal ? { signal: ctx.signal } : undefined;

    razyui(document).on('selectionchange', () => onSelectionChange(ctx), opts);

    razyui(document).on('mousedown', (e) => {
        if (ctx.slashMenuVisible && !ctx.slashMenu.contains(e.target)) {
            hideSlashMenu(ctx);
        }
    }, opts);
}

// ═══════════════════════════════════════════════
// Delegated listeners (content area, format bar, slash menu)
// ═══════════════════════════════════════════════

/**
 * Set up delegated event listeners on the content area, format bar,
 * and slash menu — replaces per-element addEventListener calls in view.js.
 * @param {Object} ctx — editor context
 */
export function initDelegatedListeners(ctx) {
    const contentEl = ctx.contentEl;

    /** Resolve the block-data object for the closest wrapper. */
    const findBlock = (target) => {
        const wrapper = target.closest('.block-wrapper');
        if (!wrapper) return null;
        return ctx.blocks.find(b => b.id === wrapper.dataset.blockId);
    };

    // ── Content area: click ──────────────────────
    contentEl.on('click', (e) => {
        // Add-block button
        const addBtn = e.target.closest('.block-add-btn');
        if (addBtn) {
            e.stopPropagation();
            const block = findBlock(addBtn);
            if (block) {
                const newBlock = ctx.addBlock('paragraph', block.id);
                ctx.focusBlock(newBlock.id);
            }
            return;
        }

        // Divider — focus next block
        const dividerWrapper = e.target.closest('.block-wrapper[data-block-type="divider"]');
        if (dividerWrapper && e.target.closest('.block-content')) {
            const block = ctx.blocks.find(b => b.id === dividerWrapper.dataset.blockId);
            if (block) {
                const idx = ctx.blocks.indexOf(block);
                if (idx < ctx.blocks.length - 1) {
                    ctx.focusBlock(ctx.blocks[idx + 1].id);
                }
            }
            return;
        }

        // Callout emoji
        const emojiBtn = e.target.closest('.block-callout-icon');
        if (emojiBtn) {
            (async () => {
                const block = findBlock(emojiBtn);
                if (!block) return;
                const Dialog = await ctx.razyui.load('Dialog');
                const emoji = await Dialog.prompt('Callout Icon', 'Enter emoji:', {
                    defaultValue: razyui(emojiBtn).text(),
                });
                if (emoji) {
                    razyui(emojiBtn).text(emoji);
                    block.meta.emoji = emoji;
                    ctx.fireChange();
                }
            })();
            return;
        }

        // Image prompt
        const imgPrompt = e.target.closest('.block-image-prompt');
        if (imgPrompt) {
            (async () => {
                const block = findBlock(imgPrompt);
                if (!block) return;
                const Dialog = await ctx.razyui.load('Dialog');
                const url = await Dialog.prompt('Image', 'Image URL:', { defaultValue: 'https://' });
                if (url) {
                    block.meta.url = url;
                    block.meta.alt = await Dialog.prompt('Image', 'Alt text:') || '';
                    ctx.rerenderBlockContent(block.id);
                    ctx.fireChange();
                }
            })();
            return;
        }
    });

    // ── Content area: pointerdown (drag handle: drag vs click) ──
    contentEl.on('pointerdown', (e) => {
        const handle = e.target.closest('.block-handle');
        if (!handle) return;
        const block = findBlock(handle);
        if (!block) return;

        // Differentiate a click (open block menu) from a drag (reorder).
        // We arm both: onDragStart starts the drag state, but we also track
        // pointer movement — if the pointer releases with < DRAG_THRESHOLD
        // of movement the block menu opens instead.
        onDragStart(ctx, e, block.id, handle);
    });

    // ── Content area: change ─────────────────────
    contentEl.on('change', (e) => {
        const checkbox = e.target.closest('.block-todo-check');
        if (checkbox) {
            const block = findBlock(checkbox);
            if (!block) return;
            block.meta.checked = checkbox.checked;
            const row = checkbox.closest('.block-todo-row');
            if (row) razyui(row).toggleClass('is-checked', checkbox.checked);
            ctx.fireChange();
        }
    });

    // ── Content area: input (code / language / toggle-summary) ──
    contentEl.on('input', (e) => {
        const langInput = e.target.closest('.block-code-lang');
        if (langInput) {
            const block = findBlock(langInput);
            if (block) {
                block.meta.language = langInput.value;
                ctx.fireChange();
            }
            return;
        }

        const codeEl = e.target.closest('.block-code');
        if (codeEl) {
            const block = findBlock(codeEl);
            if (block) {
                block.content = codeEl.textContent;
                ctx.fireChange();
            }
            return;
        }

        const summaryEl = e.target.closest('.block-toggle-summary');
        if (summaryEl) {
            const block = findBlock(summaryEl);
            if (block) {
                block.meta.summary = summaryEl.innerHTML;
                ctx.fireChange();
            }
            return;
        }
    });

    // ── Content area: keydown (code-block Tab / Enter) ──
    contentEl.on('keydown', (e) => {
        const codeEl = e.target.closest('.block-code');
        if (!codeEl) return;
        if (e.key === 'Tab') {
            e.preventDefault();
            document.execCommand('insertText', false, '    ');
        }
        if (e.key === 'Enter') {
            e.preventDefault();
            document.execCommand('insertText', false, '\n');
        }
    });

    // ── Format bar: mousedown ────────────────────
    // Dispatches to the plugin-host `formatButtons` registry. Back-compat:
    // buttons with a `cmd` string behave exactly like the legacy 5 built-ins
    // (bold/italic/strikeThrough/code/link). New buttons provide `run()`
    // and receive the current selection + pluginCtx so they own behaviour.
    ctx.formatBar.on('mousedown', (e) => {
        const btn = e.target.closest('.block-format-btn');
        if (!btn) return;
        e.preventDefault(); // keep text selection

        const buttonId = btn.getAttribute('data-btn-id');
        const registry = ctx.plugins?.formatButtons || [];
        const spec = registry.find(b => b.id === buttonId) || null;

        // Prefer the cached snapshot from ``onSelectionChange`` — it holds
        // the full cross-block span (``blockIds``) and a cloned Range that
        // survives the selection churn ``preventDefault`` can't always
        // prevent. Fall back to live ``window.getSelection`` only if the
        // cache is empty (e.g. the format bar is shown but selection was
        // invalidated between events).
        const cached = ctx.lastSelectionInfo || null;
        const sel = window.getSelection();
        const liveRange = sel && sel.rangeCount ? sel.getRangeAt(0) : null;
        const range = (cached && cached.range) || liveRange || null;
        const focused = document.activeElement;
        const blockId = (cached && cached.blockId)
            || (focused && focused.closest
                ? (focused.closest('.block-wrapper')?.dataset.blockId || null)
                : null);
        const blockIds = (cached && Array.isArray(cached.blockIds) && cached.blockIds.length)
            ? cached.blockIds
            : (blockId ? [blockId] : []);
        const block = blockId ? ctx.blocks.find(bl => bl.id === blockId) : null;
        const selectionInfo = {
            text: (cached && cached.text) || (sel ? sel.toString() : ''),
            blockId,
            blockIds,
            block,
            range,
            editableEl: focused,
            isCrossBlock: blockIds.length > 1,
        };

        // 1) Plugin-provided run() wins.
        if (spec && typeof spec.run === 'function') {
            try {
                spec.run(ctx.plugins.makePluginCtx({ owner: `format:${buttonId}` }), selectionInfo);
            } catch (err) {
                console.error(`[BlockEditor] format button "${buttonId}" threw:`, err);
            }
            // Don't auto-sync content — the plugin decides.
            return;
        }

        // 2) Legacy `cmd` path (bold / italic / strikeThrough / code / link).
        const cmd = spec?.cmd || btn.dataset.cmd;
        if (!cmd) return;
        if (cmd === 'code') {
            toggleInlineCode(ctx.contentEl[0]);
        } else if (cmd === 'link') {
            insertInlineLink(ctx.razyui, ctx.contentEl[0]);
        } else {
            document.execCommand(cmd);
        }
        if (focused && wrapper && block) {
            block.content = focused.innerHTML;
            ctx.fireChange();
        }
    });

    // ── Slash menu: click + hover ────────────────
    ctx.slashMenu.on('click', (e) => {
        const item = e.target.closest('.block-slash-item');
        if (!item) return;
        ctx.slashActiveIndex = +item.dataset.index;
        slashSelect(ctx);
    });

    ctx.slashMenu.on('mouseover', (e) => {
        const item = e.target.closest('.block-slash-item');
        if (!item) return;
        ctx.slashActiveIndex = +item.dataset.index;
        updateSlashActive(ctx);
    });
}

// ═══════════════════════════════════════════════
// Editable event binding
// ═══════════════════════════════════════════════

/**
 * Bind input, keydown, and paste events to a contenteditable element.
 * @param {Object}      ctx   — editor context
 * @param {HTMLElement}  el    — the editable element
 * @param {Object}       block — block data object
 */
export function bindEditableEvents(ctx, el, block) {
    // ── Input → sync content ──
    el.on('input', () => {
        block.content = el.html();

        // Slash command detection
        const text = el.text();
        if (text.startsWith('/')) {
            ctx.slashFilterText = text.substring(1);
            ctx.slashTargetBlockId = block.id;
            showSlashMenu(ctx, el);
        } else if (ctx.slashMenuVisible && ctx.slashTargetBlockId === block.id) {
            hideSlashMenu(ctx);
        }

        // Show/hide placeholder
        if (!el.text().trim()) {
            el.attr('data-placeholder',
                ctx.blocks.indexOf(block) === 0 && ctx.config.placeholder
                    ? ctx.config.placeholder
                    : 'Type \'/\' for commands\u2026');
        }

        ctx.fireChange();
    });

    // ── Keydown ──
    el.on('keydown', (e) => handleBlockKeydown(ctx, e, block, el));

    // ── Paste: strip formatting for code blocks ──
    el.on('paste', (e) => {
        if (block.type !== 'code') return;
        e.preventDefault();
        const text = e.clipboardData.getData('text/plain');
        document.execCommand('insertText', false, text);
    });
}

// ═══════════════════════════════════════════════
// Keyboard handling
// ═══════════════════════════════════════════════

/**
 * Handle keydown events inside a block's editable element.
 * @param {Object}        ctx   — editor context
 * @param {KeyboardEvent} e
 * @param {Object}        block — block data object
 * @param {HTMLElement}    el    — the editable element
 */
export function handleBlockKeydown(ctx, e, block, el) {
    const ctrl = e.ctrlKey || e.metaKey;

    // ── Plugin keybindings (first shot) ──
    // Skip while the slash menu is open so arrow/enter/escape still drive it.
    if (!ctx.slashMenuVisible && ctx.plugins?.handleKeydown) {
        const handled = ctx.plugins.handleKeydown(e, block.id);
        if (handled) {
            e.preventDefault();
            return;
        }
    }

    // ── Slash menu navigation ──
    if (ctx.slashMenuVisible && ctx.slashTargetBlockId === block.id) {
        if (e.key === 'ArrowDown') {
            e.preventDefault();
            slashNavigate(ctx, 1);
            return;
        }
        if (e.key === 'ArrowUp') {
            e.preventDefault();
            slashNavigate(ctx, -1);
            return;
        }
        if (e.key === 'Enter') {
            e.preventDefault();
            slashSelect(ctx);
            return;
        }
        if (e.key === 'Escape') {
            hideSlashMenu(ctx);
            return;
        }
    }

    // ── Enter: split block / create new ──
    if (e.key === 'Enter' && !e.shiftKey) {
        const sel = window.getSelection();
        if (!sel.rangeCount) return;

        const range = sel.getRangeAt(0);
        if (!range.collapsed) return;
        // Only handle caret moves that are fully inside this editable.
        // Otherwise let the default / outer behaviour through.
        if (!el[0].contains(range.commonAncestorContainer)) return;

        e.preventDefault();
        const root = el[0];

        // Range from caret → end of the editable, then extract. We use
        // explicit setStart/setEnd instead of selectNodeContents+setStart
        // (which is easier for engines to get wrong) and we snapshot the
        // plain text *before* extraction so that if `innerHTML` is empty
        // but the caret is not at EOF (a WebKit/Edge quirk with inline
        // nodes), we can still keep the characters for the new block.
        const afterRange = document.createRange();
        afterRange.setStart(range.endContainer, range.endOffset);
        const toEnd = document.createRange();
        toEnd.selectNodeContents(root);
        toEnd.collapse(false);
        afterRange.setEnd(toEnd.endContainer, toEnd.endOffset);

        const plainAfter = afterRange.toString();
        const frag = afterRange.extractContents();
        const tmp = document.createElement('div');
        if (frag) tmp.appendChild(frag);
        let afterContent = tmp.innerHTML;
        if (!String(afterContent).trim() && plainAfter) {
            afterContent = plainAfter
                .replace(/&/g, '&amp;')
                .replace(/</g, '&lt;')
                .replace(/>/g, '&gt;')
                .split('\n')
                .join('<br>');
        }

        // Update current block (everything before the caret) from the
        // live DOM after the extract.
        block.content = el.html();

        // For list/todo blocks, continue with the same type;
        // if current block is empty, convert to paragraph instead.
        const listTypes = ['bulleted-list', 'numbered-list', 'todo'];
        let newType = 'paragraph';
        let newMeta = {};
        if (listTypes.includes(block.type)) {
            if (!block.content.trim() && !String(afterContent).trim()) {
                // Empty list item → convert current to paragraph, don't add new block
                ctx.convertBlock(block.id, 'paragraph');
                requestAnimationFrame(() => ctx.focusBlock(block.id, 'start'));
                return;
            }
            newType = block.type;
            if (block.type === 'todo') newMeta = { checked: false };
        }

        const newBlock = ctx.addBlock(newType, block.id, afterContent, newMeta);
        requestAnimationFrame(() => ctx.focusBlock(newBlock.id, 'start'));
        // Enter bypasses the input event, so this path must notify hosts
        // (unsaved / dirty + plugin ``change``) explicitly — otherwise
        // split blocks look "stuck" with no version delta to save.
        ctx.fireChange();
    }

    // ── Backspace at start: merge with previous ──
    if (e.key === 'Backspace' && !ctrl) {
        const sel = window.getSelection();
        if (!sel.rangeCount) return;

        // Empty block: remove it and focus neighbour
        if (el.text() === '' && ctx.blocks.length > 1) {
            e.preventDefault();
            const idx = ctx.blocks.findIndex(b => b.id === block.id);
            const focusId = idx > 0 ? ctx.blocks[idx - 1].id : (ctx.blocks[idx + 1]?.id);
            ctx.removeBlock(block.id);
            if (focusId) ctx.focusBlock(focusId, 'end');
            return;
        }

        if (isCaretAtStart(el[0])) {
            e.preventDefault();
            // If the block starts with a structural ``<br>`` (empty first
            // line), delete that line first. ``isCaretAtStart`` is still
            // true there, so without this branch the next line would merge
            // the whole block upward on a single Backspace.
            if (tryRemoveLeadingLineBreakIfAtStart(el[0])) {
                block.content = el.html();
                ctx.fireChange();
                requestAnimationFrame(() => ctx.focusBlock(block.id, 'start'));
                return;
            }

            const idx = ctx.blocks.findIndex(b => b.id === block.id);
            if (idx <= 0) return;

            const prevBlock = ctx.blocks[idx - 1];
            if (prevBlock.type === 'divider') {
                // Just remove the divider
                ctx.removeBlock(prevBlock.id);
                return;
            }

            // Merge content into previous block
            const prevEl = ctx.getEditableInBlock(prevBlock.id);
            if (prevEl?.[0]) {
                const prevLen = prevEl.text().length;
                prevEl.html(prevEl.html() + el.html());
                prevBlock.content = prevEl.html();
                ctx.removeBlock(block.id);
                ctx.focusBlock(prevBlock.id, prevLen);
                ctx.fireChange();
            }
        }
    }

    // ── Arrow Up at start: focus previous block ──
    if (e.key === 'ArrowUp' && !e.shiftKey && isCaretAtStart(el[0])) {
        const idx = ctx.blocks.findIndex(b => b.id === block.id);
        if (idx > 0) {
            e.preventDefault();
            ctx.focusBlock(ctx.blocks[idx - 1].id, 'end');
        }
    }

    // ── Arrow Down at end: focus next block ──
    if (e.key === 'ArrowDown' && !e.shiftKey && isCaretAtEnd(el[0])) {
        const idx = ctx.blocks.findIndex(b => b.id === block.id);
        if (idx < ctx.blocks.length - 1) {
            e.preventDefault();
            ctx.focusBlock(ctx.blocks[idx + 1].id, 'start');
        }
    }

    // ── Formatting shortcuts ──
    if (ctrl) {
        switch (e.key.toLowerCase()) {
            case 'b':
                e.preventDefault();
                document.execCommand('bold');
                block.content = el.html();
                ctx.fireChange();
                break;
            case 'i':
                e.preventDefault();
                document.execCommand('italic');
                block.content = el.html();
                ctx.fireChange();
                break;
            case 'e':
                e.preventDefault();
                toggleInlineCode(ctx.contentEl[0]);
                block.content = el.html();
                ctx.fireChange();
                break;
            case 'k':
                e.preventDefault();
                insertInlineLink(ctx.razyui, ctx.contentEl[0]);
                block.content = el.html();
                ctx.fireChange();
                break;
        }
        if (e.shiftKey && e.key.toLowerCase() === 's') {
            e.preventDefault();
            document.execCommand('strikeThrough');
            block.content = el.html();
            ctx.fireChange();
        }
    }
}

// ═══════════════════════════════════════════════
// Format bar (floating toolbar on text selection)
// ═══════════════════════════════════════════════

/**
 * Resolve the block-id that a DOM node belongs to (if any).
 * @param {Node} node
 * @returns {string|null}
 */
function nodeBlockId(node) {
    if (!node) return null;
    const el = node.nodeType === Node.ELEMENT_NODE ? node : node.parentElement;
    const wrapper = el && typeof el.closest === 'function'
        ? el.closest('[data-block-id]')
        : null;
    return wrapper ? wrapper.dataset.blockId : null;
}

/**
 * Enumerate the ordered list of block-ids that a Range touches.
 *
 * Cross-block selections (mouse drag or shift+arrow across block
 * boundaries) produce a Range whose ``startContainer`` and ``endContainer``
 * live in different ``[data-block-id]`` wrappers. We walk the content
 * area in DOM order between those endpoints and collect every wrapper
 * we pass through.
 *
 * Invariant: the first entry is always the block containing the range
 * *start* (for single-block selections the only entry).
 *
 * @param {Range|null} range
 * @param {HTMLElement|null} contentRoot
 * @returns {string[]} ordered block-ids
 */
function blockIdsInRange(range, contentRoot) {
    if (!range || !contentRoot) return [];
    const startId = nodeBlockId(range.startContainer);
    const endId   = nodeBlockId(range.endContainer);
    if (!startId && !endId) return [];
    if (!startId) return [endId];
    if (!endId || startId === endId) return [startId];

    const wrappers = contentRoot.querySelectorAll('[data-block-id]');
    const ids = [];
    let collecting = false;
    for (const w of wrappers) {
        const id = w.dataset.blockId;
        if (!collecting && id === startId) collecting = true;
        if (collecting) ids.push(id);
        if (collecting && id === endId) break;
    }
    // Guard: if the DOM walk couldn't reach the end (e.g. detached range),
    // fall back to the pair we know is real.
    if (ids.length === 0) return [startId, endId];
    return ids;
}

/**
 * Handle document selection change — show or hide the inline format bar.
 *
 * Side-effects:
 *   1. Toggles ``ctx.formatBar`` visibility + position.
 *   2. Caches a rich selection snapshot on ``ctx.lastSelectionInfo`` so
 *      the format-bar mousedown handler (and plugins) can read the full
 *      cross-block selection shape even after the browser briefly
 *      collapses the selection on button press.
 *
 * NOTE: this runs on every ``selectionchange`` on the document (very
 * high-frequency). We wrap the whole body in try/catch because silent
 * failures here manifest as "the format bar never appears when I
 * select text", which is exactly the class of bug that's hardest to
 * diagnose in the wild.
 *
 * @param {Object} ctx
 */
export function onSelectionChange(ctx) {
    try {
        if (!ctx || !ctx.formatBar) return;

        const sel = window.getSelection();
        if (!sel || !sel.rangeCount || sel.isCollapsed) {
            hideFormatBar(ctx);
            return;
        }

        // Selection must be inside this editor's content area.
        const contentRoot = ctx.contentEl && ctx.contentEl[0];
        const anchor = sel.anchorNode;
        if (!anchor || !contentRoot || !contentRoot.contains(anchor)) {
            hideFormatBar(ctx);
            return;
        }

        // Don't show the format bar when the selection is inside a code
        // block — code wants its own native keyboard handling.
        const anchorEl = anchor.nodeType === Node.TEXT_NODE ? anchor.parentElement : anchor;
        if (anchorEl && anchorEl.closest && anchorEl.closest('.block-code-wrap')) {
            hideFormatBar(ctx);
            return;
        }

        const range = sel.getRangeAt(0);
        const rect = range.getBoundingClientRect();
        if (!rect || rect.width === 0) {
            hideFormatBar(ctx);
            return;
        }

        // Compute block-span: [startBlock, …, endBlock]. Single-block
        // selections yield a 1-element array; cross-block drags give us
        // the whole span in DOM order so plugins can scope correctly.
        const ids = blockIdsInRange(range, contentRoot);
        const primaryBlockId = ids[0] || null;
        const primaryBlock   = primaryBlockId
            ? ctx.blocks.find(b => b.id === primaryBlockId)
            : null;

        // Snapshot the selection so the format-bar mousedown handler
        // (and downstream plugin runs) read a consistent view even after
        // ``e.preventDefault()`` on the button briefly churns focus.
        ctx.lastSelectionInfo = {
            text: sel.toString(),
            blockId: primaryBlockId,
            blockIds: ids,
            block: primaryBlock,
            range: range.cloneRange(),
            rect,
            isCrossBlock: ids.length > 1,
        };

        const containerEl = ctx.container && ctx.container[0];
        if (!containerEl) return;
        const containerRect = containerEl.getBoundingClientRect();

        // Position the bar above the selection, centred on the rect.
        // If the selection sits near the top of the editor there's not
        // enough room above — drop the bar below the selection instead.
        const barHeight = 42;
        const preferredTop = rect.top - containerRect.top - barHeight;
        const top = preferredTop < 0
            ? (rect.bottom - containerRect.top + 8)
            : preferredTop;
        const left = rect.left - containerRect.left + rect.width / 2;
        ctx.formatBar.css('top',  `${top}px`);
        ctx.formatBar.css('left', `${left}px`);
        ctx.formatBar.addClass('is-visible');

        const wasVisible = ctx.formatBarVisible;
        ctx.formatBarVisible = true;

        // Plugin event: fire `select` when selection becomes active in the editor.
        if (!wasVisible && ctx.plugins?.emit) {
            ctx.plugins.emit('select', {
                text: ctx.lastSelectionInfo.text,
                blockId: ctx.lastSelectionInfo.blockId,
                blockIds: ctx.lastSelectionInfo.blockIds,
                isCrossBlock: ctx.lastSelectionInfo.isCrossBlock,
                rect,
            });
        }
    } catch (err) {
        // Surface, but don't let one bad selection kill the whole editor.
        // eslint-disable-next-line no-console
        console.error('[BlockEditor] onSelectionChange failed:', err);
    }
}

/**
 * Hide the inline format bar.
 * @param {Object} ctx
 */
export function hideFormatBar(ctx) {
    if (!ctx || !ctx.formatBarVisible) return;
    if (ctx.formatBar && typeof ctx.formatBar.removeClass === 'function') {
        ctx.formatBar.removeClass('is-visible');
    }
    ctx.formatBarVisible = false;
    // Drop the cached selection snapshot so stale block-ids can't leak
    // into a later plugin run if the user clicks an un-anchored button.
    ctx.lastSelectionInfo = null;
}

// ═══════════════════════════════════════════════
// Slash command menu
// ═══════════════════════════════════════════════

/**
 * Filter visible items and position the slash command menu below the caret.
 * @param {Object}      ctx
 * @param {HTMLElement}  editableEl — the editable element containing `/`
 */
export function showSlashMenu(ctx, editableEl) {
    // Filter items. Menu items carry `data-index` pointing back into
    // `ctx.slashAllItems` (source order), so we must read that — DOM order
    // may differ once items are rendered grouped.
    const filter = ctx.slashFilterText.toLowerCase();
    const items = ctx.slashMenu.find('.block-slash-item');
    let visibleCount = 0;
    items.forEach((item) => {
        const idx = +item.dataset.index;
        const bt = ctx.slashAllItems[idx];
        if (!bt) { razyui(item).css('display', 'none'); return; }
        const label   = (bt.label || '').toLowerCase();
        const desc    = (bt.desc  || '').toLowerCase();
        const type    = (bt.type  || '').toLowerCase();
        const kwords  = Array.isArray(bt.keywords) ? bt.keywords.join(' ').toLowerCase() : '';
        const match = !filter
            || label.includes(filter)
            || desc.includes(filter)
            || type.includes(filter)
            || kwords.includes(filter);
        razyui(item).css('display', match ? '' : 'none');
        if (match) visibleCount++;
    });

    if (visibleCount === 0) {
        hideSlashMenu(ctx);
        return;
    }

    // Position below caret
    const sel = window.getSelection();
    if (!sel.rangeCount) return;
    const range = sel.getRangeAt(0);
    const rect = range.getBoundingClientRect();
    const containerRect = ctx.container.getRect();

    ctx.slashMenu.css('top', `${rect.bottom - containerRect.top + 4}px`);
    ctx.slashMenu.css('left', `${rect.left - containerRect.left}px`);
    ctx.slashMenu.addClass('is-visible');
    ctx.slashMenuVisible = true;
    ctx.slashActiveIndex = 0;
    updateSlashActive(ctx);
}

/**
 * Hide the slash command menu and reset filter state.
 * @param {Object} ctx
 */
export function hideSlashMenu(ctx) {
    ctx.slashMenu.removeClass('is-visible');
    ctx.slashMenuVisible = false;
    ctx.slashFilterText = '';
    ctx.slashTargetBlockId = null;
}

/**
 * Navigate the slash menu by a step direction (+1 or -1).
 * @param {Object} ctx
 * @param {number} dir
 */
export function slashNavigate(ctx, dir) {
    const items = Array.from(ctx.slashMenu.find('.block-slash-item'))
        .filter(item => item.style.display !== 'none');
    if (!items.length) return;

    // Find current visible index
    let visibleIdx = items.findIndex(item => razyui(item).hasClass('is-active'));
    visibleIdx = ctx.razyui.clamp(visibleIdx + dir, 0, items.length - 1);

    // Map back to real index
    ctx.slashActiveIndex = +items[visibleIdx].dataset.index;
    updateSlashActive(ctx);
}

/**
 * Highlight the currently active slash menu item.
 * @param {Object} ctx
 */
export function updateSlashActive(ctx) {
    ctx.slashMenu.find('.block-slash-item').forEach((item) => {
        razyui(item).toggleClass('is-active', +item.dataset.index === ctx.slashActiveIndex);
    });
    // Scroll active into view
    const activeItem = ctx.slashMenu.find('.block-slash-item.is-active');
    if (activeItem[0]) activeItem[0].scrollIntoView({ block: 'nearest' });
}

/**
 * Execute the currently selected slash command: convert the target block
 * or invoke a custom handler.
 * @param {Object} ctx
 */
export function slashSelect(ctx) {
    const bt = ctx.slashAllItems[ctx.slashActiveIndex];
    if (!bt) return;

    const targetId = ctx.slashTargetBlockId;
    hideSlashMenu(ctx);

    const block = ctx.blocks.find(b => b.id === targetId);
    if (!block) return;

    // Clear the "/filter" text the user typed.
    block.content = '';
    const editable = ctx.getEditableInBlock(targetId);
    if (editable?.[0]) editable[0].innerHTML = '';

    // 1) Plugin slash command with run() wins.
    if (typeof bt.run === 'function') {
        try {
            const pctx = ctx.plugins?.makePluginCtx
                ? ctx.plugins.makePluginCtx({ owner: `slash:${bt.id}` })
                : null;
            bt.run(pctx, { blockId: targetId });
        } catch (err) {
            console.error(`[BlockEditor] slash command "${bt.id}" threw:`, err);
        }
        return;
    }

    // 2) Legacy customCommand handler.
    if (typeof bt.handler === 'function') {
        bt.handler(ctx.editorInstance, targetId);
        return;
    }

    // 3) Default: convert the block to the requested type.
    if (bt.type === 'divider') {
        ctx.convertBlock(targetId, 'divider', {});
    } else if (bt.type === 'image') {
        ctx.convertBlock(targetId, 'image', {});
    } else if (bt.type) {
        ctx.convertBlock(targetId, bt.type, bt.meta || {});
    }
}

// ═══════════════════════════════════════════════
// Drag and drop
// ═══════════════════════════════════════════════

/**
 * Begin pointer interaction on the drag handle.
 *
 * Interprets the gesture: if the pointer moves more than DRAG_THRESHOLD px
 * before release, it's a drag-to-reorder. Otherwise it's a click — we open
 * the block action menu (Turn into / Duplicate / Delete / Ask AI / …).
 *
 * @param {Object}       ctx
 * @param {PointerEvent} e
 * @param {string}       blockId
 * @param {HTMLElement}  [handleEl] — the drag handle that was pressed (for click anchoring)
 */
export function onDragStart(ctx, e, blockId, handleEl = null) {
    e.preventDefault();
    const DRAG_THRESHOLD = 4;
    const startX = e.clientX;
    const startY = e.clientY;
    let dragArmed = false;

    ctx.dragBlockId = blockId;

    const wrapper = ctx.blockElements.get(blockId);

    // Track which block is currently highlighted as the drop target so we
    // can toggle a ``.is-drop-target`` class and reset it cleanly on release.
    let hoveredId = null;
    const clearHovered = () => {
        if (!hoveredId) return;
        const el = ctx.blockElements.get(hoveredId);
        if (el) { el.removeClass('is-drop-target'); el.removeClass('is-drop-above'); el.removeClass('is-drop-below'); }
        hoveredId = null;
    };

    const onMove = (me) => {
        // Arm the drag only after threshold crossed.
        if (!dragArmed) {
            const dx = me.clientX - startX;
            const dy = me.clientY - startY;
            if ((dx * dx + dy * dy) < DRAG_THRESHOLD * DRAG_THRESHOLD) return;
            dragArmed = true;
            if (wrapper) wrapper.addClass('is-dragging');
            if (ctx.container) ctx.container.addClass('is-dragging-block');
        }

        const y = me.clientY;
        const contentRect = ctx.contentEl.getRect();
        let closestIdx = -1;
        let closestDist = Infinity;
        let closestBlockId = null;
        let dropAbove = true;

        ctx.blocks.forEach((b, i) => {
            const el = ctx.blockElements.get(b.id);
            if (!el || b.id === blockId) return;
            const rect = el.getRect();
            const mid = rect.top + rect.height / 2;
            const dist = Math.abs(y - mid);
            if (dist < closestDist) {
                closestDist = dist;
                closestIdx = i;
                closestBlockId = b.id;
                dropAbove = y <= mid;
                // Determine above/below
                if (y > mid) closestIdx = i + 1;
            }
        });

        ctx.dragOverIndex = ctx.razyui.clamp(closestIdx, 0, ctx.blocks.length);

        // Toggle the target-highlight class on the nearest block.
        if (closestBlockId && closestBlockId !== hoveredId) {
            clearHovered();
            hoveredId = closestBlockId;
            const el = ctx.blockElements.get(hoveredId);
            if (el) el.addClass('is-drop-target');
        }
        if (hoveredId) {
            const el = ctx.blockElements.get(hoveredId);
            if (el) {
                if (dropAbove) { el.addClass('is-drop-above'); el.removeClass('is-drop-below'); }
                else           { el.addClass('is-drop-below'); el.removeClass('is-drop-above'); }
            }
        }

        // Show the thin accent bar between blocks.
        if (ctx.dragOverIndex >= 0) {
            const refBlock = ctx.blocks[Math.min(ctx.dragOverIndex, ctx.blocks.length - 1)];
            const refEl = ctx.blockElements.get(refBlock?.id);
            if (refEl) {
                const refRect = refEl.getRect();
                const top = ctx.dragOverIndex >= ctx.blocks.length
                    ? refRect.bottom - contentRect.top
                    : refRect.top - contentRect.top;
                const offsetTop = (ctx.contentEl.prop && ctx.contentEl.prop('offsetTop')) || 0;
                ctx.dragIndicator.css('top', `${top + offsetTop}px`);
                ctx.dragIndicator.addClass('is-visible');
            }
        }
    };

    const onUp = () => {
        razyui(document).off('pointermove', onMove);
        razyui(document).off('pointerup', onUp);

        if (wrapper) wrapper.removeClass('is-dragging');
        if (ctx.container) ctx.container.removeClass('is-dragging-block');
        clearHovered();
        ctx.dragIndicator.removeClass('is-visible');

        if (dragArmed) {
            // Drag finished → reorder
            if (ctx.dragOverIndex >= 0 && ctx.dragBlockId) {
                const fromIdx = ctx.blocks.findIndex(b => b.id === ctx.dragBlockId);
                let toIdx = ctx.dragOverIndex;
                if (toIdx > fromIdx) toIdx--;
                if (fromIdx !== toIdx) {
                    ctx.moveBlock(ctx.dragBlockId, toIdx);
                }
            }
        } else {
            // No drag → treat as a click → open block action menu
            openBlockMenu(ctx, ctx.dragBlockId, handleEl);
        }

        ctx.dragBlockId = null;
        ctx.dragOverIndex = -1;
    };

    razyui(document).on('pointermove', onMove);
    razyui(document).on('pointerup', onUp);
}

// ═══════════════════════════════════════════════
// Block action menu (drag-handle click)
// ═══════════════════════════════════════════════

/**
 * Open the per-block action menu anchored to the drag handle.
 * @param {Object}      ctx
 * @param {string}      blockId
 * @param {HTMLElement} [anchor]
 */
export function openBlockMenu(ctx, blockId, anchor) {
    if (!ctx.plugins) return;
    const menuEl = buildBlockMenu(ctx, blockId);
    // Focus the block so plugin "run" handlers can read selection/focus state.
    ctx.focusBlock(blockId);

    const overlay = ctx.plugins.mountOverlay(menuEl, {
        anchor: anchor || ctx.blockElements.get(blockId)?.[0] || null,
        placement: 'right-start',
        offset: 6,
        // IMPORTANT: do NOT destroy the submenu from here. When the user
        // clicks inside the submenu, the document-capture ``mousedown`` on
        // this parent overlay fires first (submenu is outside the parent's
        // element), so tearing the submenu down here would detach the
        // clicked row before its ``click`` ever fires — which is exactly
        // how "Turn into …" pickers silently no-op'd before. Instead we
        // keep the submenu alive through the parent's outside-click; the
        // submenu has its own closeOnOutsideClick handler to die cleanly
        // when the click lands outside BOTH menus.
    });

    // ── Nested submenu state (hover-opened, Notion-style) ────────────────
    // Only one submenu can be open at a time. We keep a soft-close timer so
    // the user can move the cursor from the parent row into the submenu
    // without it flickering shut.
    let submenuOverlay = null;
    let submenuRow     = null;   // the parent row that opened the submenu
    let submenuSpecId  = null;   // id of the block-menu spec that's open
    let closeTimer     = null;

    const HOVER_CLOSE_DELAY = 180;

    function cancelClose() {
        if (closeTimer) { clearTimeout(closeTimer); closeTimer = null; }
    }
    function closeSubmenu() {
        cancelClose();
        if (submenuOverlay) { try { submenuOverlay.destroy(); } catch (_) {} }
        submenuOverlay = null;
        submenuRow     = null;
        submenuSpecId  = null;
    }
    function scheduleClose() {
        cancelClose();
        closeTimer = setTimeout(closeSubmenu, HOVER_CLOSE_DELAY);
    }

    function openSubmenuForRow(row, spec) {
        if (!row || !spec || typeof spec.submenu !== 'function') return;
        // Already open for this row → nothing to do.
        if (submenuOverlay && submenuSpecId === spec.id) { cancelClose(); return; }
        // Different submenu currently open → swap it out cleanly.
        if (submenuOverlay) closeSubmenu();

        let built;
        try {
            built = spec.submenu(
                ctx.plugins.makePluginCtx({ owner: `blockmenu:${spec.id}:submenu` }),
                { blockId },
            );
        } catch (err) {
            console.error(`[BlockEditor] block-menu "${spec.id}" submenu threw:`, err);
            return;
        }
        if (!built || !built.el) return;

        submenuRow    = row;
        submenuSpecId = spec.id;
        submenuOverlay = ctx.plugins.mountOverlay(built.el, {
            anchor: row,
            placement: 'right-start',
            offset: 4,
            // Parent overlay already handles escape/outside-click; we let
            // mousedown-outside close the submenu too so it feels snappy.
        });

        // Keep the submenu alive while the cursor is inside it.
        built.el.addEventListener('mouseenter', cancelClose);
        built.el.addEventListener('mouseleave', scheduleClose);

        // Pick handler → apply + tear both menus down.
        built.el.addEventListener('click', (ev) => {
            if (typeof built.onPick !== 'function') return;
            let picked = false;
            try { picked = !!built.onPick(ev.target); } catch (err) {
                console.error(`[BlockEditor] block-menu "${spec.id}" onPick threw:`, err);
            }
            if (picked) {
                closeSubmenu();
                overlay.destroy();
            }
        });
    }

    // ── Mouseover: open submenu for hover-enabled rows, close it for others.
    menuEl.addEventListener('mouseover', (ev) => {
        const row = ev.target.closest('.block-handle-menu-item');
        if (!row || !menuEl.contains(row)) return;
        cancelClose();
        const id = row.getAttribute('data-menu-id');
        const spec = (ctx.plugins.blockMenuItems || []).find(it => it.id === id);
        if (spec && spec.hasSubmenu) {
            openSubmenuForRow(row, spec);
        } else if (submenuOverlay) {
            // Moved to a non-submenu row → dismiss with a short grace period
            // (so the cursor can still slip through into an open submenu).
            scheduleClose();
        }
    });

    // Leaving the parent menu entirely: let the submenu's own mouseenter
    // cancel the close if the cursor lands inside it.
    menuEl.addEventListener('mouseleave', scheduleClose);

    // ── Click: submenu items defer to hover; other items run + close.
    const onClick = (ev) => {
        const row = ev.target.closest('.block-handle-menu-item');
        if (!row) return;
        const id = row.getAttribute('data-menu-id');
        const spec = (ctx.plugins.blockMenuItems || []).find(it => it.id === id);
        if (spec && spec.hasSubmenu) {
            // Click on a submenu-parent row: open it immediately for users on
            // touch / keyboard / accessibility paths where hover isn't available.
            openSubmenuForRow(row, spec);
            return;
        }
        // Normal row pick → close everything (including any open submenu).
        closeSubmenu();
        overlay.destroy();
        if (!spec || typeof spec.run !== 'function') return;
        try {
            spec.run(ctx.plugins.makePluginCtx({ owner: `blockmenu:${id}` }), { blockId });
        } catch (err) {
            console.error(`[BlockEditor] block-menu "${id}" threw:`, err);
        }
    };
    menuEl.addEventListener('click', onClick);
}
