/**
 * @fileoverview BlockEditor barrel — re-exports from modular implementation.
 * Kept at module root for backward compatibility with razyui.load().
 *
 * @module module/BlockEditor
 */
import { default as razyui } from '../index.js';
import { BlockEditorDef as DEF } from './BlockEditor.def.js';
import BlockEditor from './BlockEditor/index.js';
import { aiSkillsPlugin, DEFAULT_SKILLS } from './BlockEditor/plugins/ai-skills.js';

// NOTE: We intentionally do NOT ``import '../sass/component/BlockEditor.css'``
// here. Doing so turns the static sheet into a hard sibling-chunk dependency
// on RazyUI's prebuilt dist (``dist/assets/BlockEditor-<hash>.css``) which
// downstream re-bundlers (oaao.ai, Razy-Dev) don't always carry — the result
// is a 404 on ``__vitePreload`` and a broken editor.
//
// The JIT pipeline already compiles all PART.*.jit strings into the host's
// CSS, including ``.is-visible`` states for the format bar and slash menu.
// Consumers that want the static Notion baseline (docs site, plain-HTML
// embeds, non-JIT hosts) can opt in explicitly:
//
//   import 'razyui/src/sass/component/BlockEditor.css'; // or copy it
//
// This keeps the component module pure and the load graph flat.

// -- First-party plugin surface --
// Expose built-in plugins as a static namespace so host apps can
// reach them via ``razyui.load('BlockEditor').plugins.aiSkills``
// without a second loader call. Keeps the load graph flat and
// preserves tree-shaking for apps that don't use AI.
BlockEditor.plugins = Object.assign({}, BlockEditor.plugins, {
    aiSkills: aiSkillsPlugin,
    aiSkillsDefaults: DEFAULT_SKILLS,
});

// -- Module registration --
razyui.BlockEditor = BlockEditor;

// -- JIT Component Definition registration --
if (razyui.JIT?.defineComponent) {
    razyui.JIT.defineComponent(DEF.name, DEF);
}

/**
 * Registers the custom element for the BlockEditor component.
 * Defines the custom element using the tag and observed attributes from the component definition.
 * 
 * @function registerElement
 * @returns {Promise<void>} A promise that resolves when the element is registered.
 */
export async function registerElement() {
    const ce = await razyui.ce?.();
    ce?.registerFromDef?.(DEF, BlockEditor);
}

export default BlockEditor;
export { aiSkillsPlugin, DEFAULT_SKILLS } from './BlockEditor/plugins/ai-skills.js';
export const stylesheet = null;
