/**
 * @fileoverview BlockEditor helpers — pure utility functions for HTML/Markdown
 *               conversion, caret/selection inspection, inline formatting,
 *               and lazy module loading.
 *
 * @module module/BlockEditor/helpers
 */

import razyui from '../../index.js';

// ═══════════════════════════════════════════════
// Block IDs — stable UUID v4 per block
// ═══════════════════════════════════════════════

/**
 * Generate a stable v4 UUID for a new block.
 *
 * Matches Notion's wire format (``xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx``)
 * so server-side sees a real UUID regardless of how many round-trips the
 * block has been through. Two layers of fallback keep the editor usable
 * in every environment we ship into:
 *
 *   1. ``crypto.randomUUID``  — modern browsers (secure contexts)
 *   2. ``crypto.getRandomValues`` pairing — non-secure contexts that still
 *      expose ``window.crypto`` (most Electron renderers, http:// dev)
 *   3. ``razyui.hash`` pair    — last-resort polyfill (random-ish, not a
 *      real v4 UUID but conforms to the same dash-separated shape so
 *      downstream code never has to special-case the length).
 *
 * @returns {string}
 */
export function newBlockId() {
    try {
        if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') {
            return crypto.randomUUID();
        }
    } catch (_) { /* fall through */ }

    try {
        if (typeof crypto !== 'undefined' && typeof crypto.getRandomValues === 'function') {
            const bytes = new Uint8Array(16);
            crypto.getRandomValues(bytes);
            // Per RFC 4122 §4.4 — set version + variant bits.
            bytes[6] = (bytes[6] & 0x0f) | 0x40;
            bytes[8] = (bytes[8] & 0x3f) | 0x80;
            const hex = [...bytes].map(b => b.toString(16).padStart(2, '0'));
            return (
                hex.slice(0, 4).join('') + '-' +
                hex.slice(4, 6).join('') + '-' +
                hex.slice(6, 8).join('') + '-' +
                hex.slice(8, 10).join('') + '-' +
                hex.slice(10, 16).join('')
            );
        }
    } catch (_) { /* fall through */ }

    // Last-resort polyfill — still uuid-shaped so server validation
    // (if any) doesn't reject it, but not cryptographically random.
    const h = razyui && typeof razyui.hash === 'function'
        ? (n) => razyui.hash(n)
        : (n) => Math.random().toString(16).slice(2, 2 + n);
    return `${h(8)}-${h(4)}-4${h(3)}-${['8','9','a','b'][Math.floor(Math.random() * 4)]}${h(3)}-${h(12)}`;
}

// ═══════════════════════════════════════════════
// Lazy MarkdownEditor loader
// ═══════════════════════════════════════════════

/** @type {Function|null} Cached MarkdownEditor constructor. */
let _MarkdownEditor = null;

/**
 * Lazy-load the MarkdownEditor module (only fetched when actually needed).
 * @returns {Promise<Function>}
 */
export async function getMarkdownEditor() {
    if (!_MarkdownEditor) {
        const mod = await import('../MarkdownEditor.js');
        _MarkdownEditor = mod.default;
    }
    return _MarkdownEditor;
}

// ═══════════════════════════════════════════════
// HTML ↔ Markdown conversion
// ═══════════════════════════════════════════════

/**
 * Convert inline HTML back to Markdown syntax.
 * @param {string} html
 * @returns {string}
 */
export function htmlToMd(html) {
    if (!html) return '';
    let md = html;
    md = md.replace(/<strong>(.*?)<\/strong>/gi, '**$1**');
    md = md.replace(/<b>(.*?)<\/b>/gi, '**$1**');
    md = md.replace(/<em>(.*?)<\/em>/gi, '*$1*');
    md = md.replace(/<i>(.*?)<\/i>/gi, '*$1*');
    md = md.replace(/<del>(.*?)<\/del>/gi, '~~$1~~');
    md = md.replace(/<s>(.*?)<\/s>/gi, '~~$1~~');
    md = md.replace(/<code>(.*?)<\/code>/gi, '`$1`');
    md = md.replace(/<mark>(.*?)<\/mark>/gi, '==$1==');
    md = md.replace(/<a\s[^>]*href="([^"]*)"[^>]*>(.*?)<\/a>/gi, '[$2]($1)');
    md = md.replace(/<br\s*\/?>/gi, '\n');
    md = md.replace(/<[^>]+>/g, '');
    md = md.replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"');
    return md;
}

// ═══════════════════════════════════════════════
// Caret / selection utilities
// ═══════════════════════════════════════════════

/**
 * Check whether the caret sits at the very start of an element.
 * @param {Element} el
 * @returns {boolean}
 */
export function isCaretAtStart(el) {
    const sel = window.getSelection();
    if (!sel.rangeCount || !sel.isCollapsed) return false;
    const range = sel.getRangeAt(0);

    const preRange = document.createRange();
    preRange.selectNodeContents(el);
    preRange.setEnd(range.startContainer, range.startOffset);
    return preRange.toString().length === 0;
}

/**
 * Check whether the caret sits at the very end of an element.
 * @param {Element} el
 * @returns {boolean}
 */
export function isCaretAtEnd(el) {
    const sel = window.getSelection();
    if (!sel.rangeCount || !sel.isCollapsed) return false;
    const range = sel.getRangeAt(0);

    const postRange = document.createRange();
    postRange.selectNodeContents(el);
    postRange.setStart(range.endContainer, range.endOffset);
    return postRange.toString().length === 0;
}

/**
 * When the caret is at the start of a block, contenteditable often keeps a
 * leading line break as a ``<br>`` (empty first line) before the real text.
 * ``isCaretAtStart`` is still true because there is no *text* before the
 * caret, so the Backspace handler would otherwise merge with the **previous
 * block** on the first keypress. Users expect: first Backspace removes that
 * empty first line, second Backspace (still at the merge boundary) performs
 * the block merge.
 *
 * @param {Element} el — native contenteditable element
 * @returns {boolean} true if a leading ``<br>`` was removed
 */
export function tryRemoveLeadingLineBreakIfAtStart(el) {
    if (!isCaretAtStart(el)) return false;
    // A leading ``<br>`` (empty first "line" before the rest of the
    // block) is often `el`''s *first* child, whether the collapsed caret
    // is at ``(el,0)`` or in the first text/inline that follows — and
    // ``<br>`` does not add to ``Range#toString()``, so we still
    // classify as *start* here.  Mid-paragraph breaks (e.g. ``a<br>b``)
    // are not at the block start, so this does not fire.
    const first = el.firstChild;
    if (first && first.nodeName === 'BR' && first.nextSibling) {
        first.remove();
        return true;
    }
    return false;
}

// ═══════════════════════════════════════════════
// Inline formatting helpers
// ═══════════════════════════════════════════════

/**
 * Toggle an inline `<code>` wrapper around the current selection.
 * @param {Element} contentEl — content boundary element
 */
export function toggleInlineCode(contentEl) {
    const sel = window.getSelection();
    if (!sel.rangeCount || sel.isCollapsed) return;

    const range = sel.getRangeAt(0);
    const selected = range.toString();
    if (!selected) return;

    // Check if already inside a <code>
    const parent = razyui(range.commonAncestorContainer).closest('code', contentEl);
    if (parent.length) {
        // Unwrap
        const text = document.createTextNode(parent.text());
        parent[0].replaceWith(text);
        return;
    }

    // Wrap in <code>
    const code = razyui.el('code');
    range.surroundContents(code[0]);
}

/**
 * Prompt the user for a URL and insert an inline link at the current
 * selection (or insert the raw URL if nothing is selected).
 * @param {Object}  razyui    — razyui module reference
 * @param {Element} contentEl — content boundary element
 */
export async function insertInlineLink(razyui, contentEl) {
    const sel = window.getSelection();
    if (!sel.rangeCount) return;
    const text = sel.toString();
    const Dialog = await razyui.load('Dialog');
    const url = await Dialog.prompt('Insert Link', 'Enter URL:', { defaultValue: 'https://' });
    if (!url) return;

    if (text) {
        document.execCommand('createLink', false, url);
        // Set target=_blank on newly created link
        razyui(contentEl).find('a[href="' + url + '"]').each(a => {
            a.target = '_blank';
            a.rel = 'noopener';
        });
    } else {
        document.execCommand('insertHTML', false, `<a href="${url}" target="_blank" rel="noopener">${url}</a>`);
    }
}
