/**
 * @fileoverview BlockEditor state — reactive state factory.
 *
 * Wraps `razyui.state()` to produce the editor's reactive
 * `[stateRef, setState]` pair.
 *
 * @module module/BlockEditor/state
 */

/**
 * Create the reactive state pair for the block editor.
 * @param {Object} razyui — razyui module reference
 * @returns {[Object, Function]} [stateRef, setState]
 */
export function createState(razyui) {
    return razyui.state({ blockCount: 0 });
}
