/**
 * @fileoverview AI Skills plugin for BlockEditor — Notion-style inline AI menu.
 *
 * Provides three surfaces:
 *   1. Format-bar button ("✨ Ask AI") — opens a floating popover of skills
 *      anchored above the current selection.
 *   2. Slash-menu group "Ask AI" — each skill appears as a slash command
 *      when the user types `/` on an empty or short-content line.
 *   3. Block action menu (drag-handle click) — "Ask AI" submenu.
 *
 * The plugin is a thin UI layer. The actual LLM call is delegated to the
 * `askAI` callback you pass in, so prompts/endpoints live in your app code
 * (or in a sidecar proto — see library-page/index.js for a reference
 * integration using proposeLibraryEdits).
 *
 * Shape of the `askAI` callback:
 *
 *   askAI({ skill, skillId, selection, block, blocks, signal })
 *     → Promise<{
 *         mode: 'replace-selection' | 'replace-block' | 'insert-after' | 'diff' | 'noop',
 *         text?: string,                // for replace-* and insert-after
 *         blocks?: Array,               // for mode='diff' (caller owns UI)
 *         message?: string,             // optional toast content
 *       }>
 *
 * @module module/BlockEditor/plugins/ai-skills
 */

/**
 * Default skill catalog, loosely mirroring Notion's skills grouping.
 * Each skill is passed back to `askAI({ skill, skillId })`.
 */
export const DEFAULT_SKILLS = Object.freeze([
    { id: 'improve-writing', label: 'Improve writing',     desc: 'Polish the selected text',         group: 'Edit',     icon: '\u270E' },
    { id: 'proofread',       label: 'Fix spelling & grammar', desc: 'Proofread the selection',       group: 'Edit',     icon: '\u2713' },
    { id: 'make-shorter',    label: 'Make shorter',        desc: 'Condense while keeping meaning',    group: 'Edit',     icon: '\u21E3' },
    { id: 'make-longer',     label: 'Make longer',         desc: 'Expand with more detail',           group: 'Edit',     icon: '\u21E1' },
    { id: 'change-tone',     label: 'Change tone\u2026',   desc: 'Rewrite in a different tone',       group: 'Edit',     icon: '\uD83C\uDFAD' },
    { id: 'translate',       label: 'Translate\u2026',     desc: 'Translate to another language',     group: 'Edit',     icon: '\uD83C\uDF10' },
    { id: 'explain',         label: 'Explain this',        desc: 'Explain in simpler terms',          group: 'Generate', icon: '\uD83D\uDCA1' },
    { id: 'summarize',       label: 'Summarize',           desc: 'TL;DR of the selection',            group: 'Generate', icon: '\u2261' },
    { id: 'continue-writing',label: 'Continue writing',    desc: 'Continue from the cursor',          group: 'Generate', icon: '\u21AA' },
    { id: 'action-items',    label: 'Find action items',   desc: 'Extract todos from the text',       group: 'Generate', icon: '\u2611' },
]);

/**
 * Apply the AI response to the editor based on `mode`.
 * @private
 */
function applyAiResult(pluginCtx, targetBlockId, selection, result) {
    if (!result || result.mode === 'noop') return;

    switch (result.mode) {
        case 'replace-selection': {
            if (!selection || !selection.range) return;
            const text = String(result.text || '');
            const range = selection.range;
            range.deleteContents();
            range.insertNode(document.createTextNode(text));
            // Trigger the editable's input handler so it syncs block.content
            // and fires the editor's change pipeline (onChange / rui-change).
            const blockId = targetBlockId || selection.blockId;
            const editable = blockId
                ? pluginCtx.container.querySelector(`[data-block-id="${blockId}"] [contenteditable="true"]`)
                : null;
            if (editable) editable.dispatchEvent(new Event('input', { bubbles: true }));
            break;
        }
        case 'replace-block': {
            if (!targetBlockId) return;
            pluginCtx.updateBlock(targetBlockId, { content: String(result.text || '') });
            break;
        }
        case 'insert-after': {
            if (!targetBlockId) return;
            pluginCtx.addBlock('paragraph', targetBlockId, String(result.text || ''));
            break;
        }
        case 'diff': {
            // Caller owns the diff UI; the plugin just surfaces the event.
            pluginCtx.emit('ai:diff', { blockId: targetBlockId, blocks: result.blocks || [], message: result.message });
            break;
        }
        default:
            break;
    }
}

/**
 * Install the shared keyframes stylesheet used by the generating/proposal
 * pills. Idempotent — called from every pill factory.
 * @private
 */
function installPillStyles() {
    if (document.getElementById('block-ai-pill-keyframes')) return;
    const style = document.createElement('style');
    style.id = 'block-ai-pill-keyframes';
    style.textContent =
        '@keyframes block-ai-pulse{0%,100%{opacity:0.55;transform:scale(0.95);}50%{opacity:1;transform:scale(1.05);}}';
    document.head.appendChild(style);
}

/**
 * Extract a human-readable preview of the proposed edit from an askAI
 * result. Used in the Accept/Decline pill so the user knows what they're
 * agreeing to without having to diff it in their head.
 * @private
 */
function resultPreviewText(result) {
    if (!result) return '';
    if (typeof result.text === 'string' && result.text.trim()) return result.text;
    if (Array.isArray(result.blocks) && result.blocks.length) {
        return result.blocks
            .map(b => String((b && (b.proposed ?? b.content)) || '').trim())
            .filter(Boolean)
            .join('\n\n');
    }
    if (typeof result.message === 'string') return result.message;
    return '';
}

/**
 * Render a Notion-style "AI suggestion" pill under the anchor block with
 * Accept / Decline buttons. Returns a ``dismiss()`` fn callers should
 * invoke to remove the pill programmatically (e.g. on editor teardown).
 *
 * Buttons call the supplied callbacks *and* dismiss the pill — consumers
 * don't need to dismiss inside their handlers.
 *
 * @param {Object}   ctx
 * @param {Object}   opts
 * @param {string|null} opts.blockId   — anchor block the pill is pinned to
 * @param {string}   [opts.label='AI suggestion']
 * @param {string}   [opts.previewText='']
 * @param {string}   [opts.mode='']    — result.mode, surfaced as a subtle tag
 * @param {() => void} opts.onAccept
 * @param {() => void} opts.onDecline
 * @returns {() => void} dismiss
 * @private
 */
function showProposalPreview(ctx, {
    blockId,
    label = 'AI suggestion',
    previewText = '',
    mode = '',
    onAccept,
    onDecline,
}) {
    const container = ctx.container;
    if (!container || !container.appendChild) return () => {};
    installPillStyles();

    const anchor = blockId
        ? container.querySelector(`[data-block-id="${CSS && CSS.escape ? CSS.escape(blockId) : blockId}"]`)
        : null;

    const pill = document.createElement('div');
    pill.className = 'block-ai-proposal-pill';
    pill.setAttribute('data-skill-pill', '1');
    pill.setAttribute('role', 'group');
    pill.style.cssText = [
        'display:flex',
        'flex-direction:column',
        'gap:8px',
        'margin:4px 2px 6px var(--be-row-indent, 50px)',
        'padding:10px 12px',
        'background:var(--be-bg-raised, #FFFFFF)',
        'border:1px solid var(--be-border, rgba(55,53,47,0.16))',
        'border-left:3px solid var(--be-accent, #2383E2)',
        'border-radius:6px',
        'box-shadow:0 1px 2px rgba(15,15,15,0.04)',
        'color:var(--be-text, rgba(55,53,47,0.85))',
        'font-size:0.875em',
        'line-height:1.5',
    ].join(';');

    // Header row: sparkle + label + mode tag + close.
    const header = document.createElement('div');
    header.style.cssText = 'display:flex;align-items:center;gap:8px;';
    const sparkle = document.createElement('span');
    sparkle.textContent = '\u2728';
    sparkle.style.cssText = 'color:var(--be-accent, #2383E2);font-size:14px;line-height:1;';
    const title = document.createElement('span');
    title.textContent = label;
    title.style.cssText = 'flex:1;font-weight:600;color:var(--be-text, rgba(55,53,47,0.85));';
    header.appendChild(sparkle);
    header.appendChild(title);
    if (mode) {
        const tag = document.createElement('span');
        tag.textContent = mode;
        tag.style.cssText = [
            'font-size:0.72em',
            'font-weight:500',
            'padding:1px 6px',
            'border-radius:10px',
            'background:var(--be-bg-inset, rgba(55,53,47,0.06))',
            'color:var(--be-text-muted, rgba(55,53,47,0.55))',
            'letter-spacing:0.02em',
            'text-transform:uppercase',
        ].join(';');
        header.appendChild(tag);
    }

    // Preview body — clamped to 5 lines so the pill doesn't dominate
    // the viewport for long rewrites. User can still scroll inside.
    const body = document.createElement('div');
    const clean = String(previewText || '').replace(/[<>&]/g, (c) => ({'<':'&lt;','>':'&gt;','&':'&amp;'}[c])) || '<span style="opacity:0.6;">(empty response)</span>';
    body.innerHTML = clean.replace(/\n/g, '<br>');
    body.style.cssText = [
        'max-height:140px',
        'overflow:auto',
        'white-space:pre-wrap',
        'word-break:break-word',
        'padding:6px 8px',
        'background:var(--be-bg-inset, rgba(55,53,47,0.03))',
        'border-radius:4px',
        'color:var(--be-text, rgba(55,53,47,0.85))',
        'font-size:0.95em',
    ].join(';');

    // Actions row.
    const actions = document.createElement('div');
    actions.style.cssText = 'display:flex;justify-content:flex-end;gap:8px;';

    const declineBtn = document.createElement('button');
    declineBtn.type = 'button';
    declineBtn.textContent = 'Discard';
    declineBtn.style.cssText = [
        'padding:4px 12px',
        'border:1px solid var(--be-border, rgba(55,53,47,0.16))',
        'background:var(--be-bg-raised, #FFFFFF)',
        'color:var(--be-text, rgba(55,53,47,0.65))',
        'border-radius:4px',
        'cursor:pointer',
        'font-size:0.875em',
        'font-weight:500',
        'transition:background 100ms',
    ].join(';');
    declineBtn.addEventListener('mouseenter', () => { declineBtn.style.background = 'var(--be-bg-hover, rgba(55,53,47,0.06))'; });
    declineBtn.addEventListener('mouseleave', () => { declineBtn.style.background = 'var(--be-bg-raised, #FFFFFF)'; });

    const acceptBtn = document.createElement('button');
    acceptBtn.type = 'button';
    acceptBtn.textContent = 'Accept';
    acceptBtn.style.cssText = [
        'padding:4px 14px',
        'border:1px solid transparent',
        'background:var(--be-accent, #2383E2)',
        'color:#FFFFFF',
        'border-radius:4px',
        'cursor:pointer',
        'font-size:0.875em',
        'font-weight:600',
        'transition:filter 100ms',
    ].join(';');
    acceptBtn.addEventListener('mouseenter', () => { acceptBtn.style.filter = 'brightness(0.93)'; });
    acceptBtn.addEventListener('mouseleave', () => { acceptBtn.style.filter = 'none'; });

    actions.appendChild(declineBtn);
    actions.appendChild(acceptBtn);

    pill.appendChild(header);
    pill.appendChild(body);
    pill.appendChild(actions);

    if (anchor && anchor.parentNode) {
        anchor.parentNode.insertBefore(pill, anchor.nextSibling);
    } else {
        container.appendChild(pill);
    }

    let dismissed = false;
    const dismiss = () => {
        if (dismissed) return;
        dismissed = true;
        if (pill.parentNode) pill.parentNode.removeChild(pill);
    };

    declineBtn.addEventListener('click', (ev) => {
        ev.preventDefault();
        ev.stopPropagation();
        try { onDecline && onDecline(); } catch (err) { console.error('[ai-skills] onDecline threw:', err); }
        dismiss();
    });
    acceptBtn.addEventListener('click', (ev) => {
        ev.preventDefault();
        ev.stopPropagation();
        try { onAccept && onAccept(); } catch (err) { console.error('[ai-skills] onAccept threw:', err); }
        dismiss();
    });

    // Accept on Enter, Discard on Escape — only when focus is inside the
    // pill. This lets keyboard users drive the confirmation without
    // reaching for the mouse.
    pill.addEventListener('keydown', (ev) => {
        if (ev.key === 'Enter') { ev.preventDefault(); acceptBtn.click(); }
        else if (ev.key === 'Escape') { ev.preventDefault(); declineBtn.click(); }
    });
    // Move focus to Accept so Enter works immediately.
    requestAnimationFrame(() => { try { acceptBtn.focus(); } catch (_) {} });

    return dismiss;
}

/**
 * Show a Notion-style "Generating…" pill inline, anchored directly beneath
 * the target block. Returns a ``dismiss()`` function the caller MUST invoke
 * on completion/error so the pill is removed.
 *
 * The pill surfaces three things to the user:
 *   1. Confirmation that their Ask-AI click was received.
 *   2. Which block is being worked on (visual anchoring).
 *   3. A stop button that aborts the in-flight request.
 *
 * Implementation note: we insert the pill as a *sibling node* right after
 * the block wrapper rather than a floating popover, so it naturally flows
 * with scrolling and reorders when the user drags blocks around.
 *
 * @param {Object}          ctx
 * @param {Object}          opts
 * @param {string|null}     opts.blockId     — anchor block
 * @param {AbortController} opts.controller
 * @param {string}          [opts.label='Generating']
 * @returns {() => void} dismiss
 * @private
 */
function showGeneratingPill(ctx, { blockId, controller, label = 'Generating' }) {
    // Find the anchor block in the DOM. Fall back to appending at the end
    // of the content area if we can't locate it (e.g. if the block was
    // deleted mid-flight) — users still get the feedback.
    const container = ctx.container;
    if (!container || !container.appendChild) return () => {};

    const anchor = blockId
        ? container.querySelector(`[data-block-id="${CSS && CSS.escape ? CSS.escape(blockId) : blockId}"]`)
        : null;

    const pill = document.createElement('div');
    pill.className = 'block-ai-generating-pill';
    pill.setAttribute('data-skill-pill', '1');
    pill.setAttribute('role', 'status');
    pill.setAttribute('aria-live', 'polite');
    // Match the inline feel: fill the row (minus left controls column),
    // rounded corners, faint border, subtle breathing pulse. Colour tokens
    // fall back to Notion-ish defaults when the host theme has no values.
    pill.style.cssText = [
        'display:flex',
        'align-items:center',
        'gap:8px',
        'margin:4px 2px 4px var(--be-row-indent, 50px)',
        'padding:8px 10px 8px 12px',
        'background:var(--be-bg-raised, #FFFFFF)',
        'border:1px solid var(--be-border, rgba(55,53,47,0.16))',
        'border-radius:6px',
        'box-shadow:0 1px 2px rgba(15,15,15,0.04)',
        'color:var(--be-text-muted, rgba(55,53,47,0.65))',
        'font-size:0.875em',
        'line-height:1.4',
        'user-select:none',
        'pointer-events:auto',
    ].join(';');

    const sparkle = document.createElement('span');
    sparkle.textContent = '\u2728';
    sparkle.style.cssText = [
        'display:inline-flex',
        'align-items:center',
        'justify-content:center',
        'width:18px',
        'height:18px',
        'color:var(--be-accent, #2383E2)',
        'animation:block-ai-pulse 1400ms ease-in-out infinite',
    ].join(';');

    const text = document.createElement('span');
    text.textContent = label;
    text.style.cssText = 'flex:1;color:var(--be-text-muted, rgba(55,53,47,0.65));';

    const stopBtn = document.createElement('button');
    stopBtn.type = 'button';
    stopBtn.setAttribute('aria-label', 'Stop');
    stopBtn.setAttribute('title', 'Stop');
    stopBtn.textContent = '\u25A0'; // ■
    stopBtn.style.cssText = [
        'display:inline-flex',
        'align-items:center',
        'justify-content:center',
        'width:22px',
        'height:22px',
        'border:none',
        'background:var(--be-bg-inset, rgba(55,53,47,0.06))',
        'color:var(--be-text, rgba(55,53,47,0.65))',
        'border-radius:4px',
        'cursor:pointer',
        'font-size:10px',
        'line-height:1',
        'padding:0',
        'transition:background 100ms',
    ].join(';');
    stopBtn.addEventListener('mouseenter', () => {
        stopBtn.style.background = 'var(--be-bg-hover, rgba(55,53,47,0.08))';
    });
    stopBtn.addEventListener('mouseleave', () => {
        stopBtn.style.background = 'var(--be-bg-inset, rgba(55,53,47,0.06))';
    });
    stopBtn.addEventListener('click', (ev) => {
        ev.preventDefault();
        ev.stopPropagation();
        try { controller && controller.abort(); } catch (_) { /* ignore */ }
        dismiss();
    });

    pill.appendChild(sparkle);
    pill.appendChild(text);
    pill.appendChild(stopBtn);

    installPillStyles();

    if (anchor && anchor.parentNode) {
        anchor.parentNode.insertBefore(pill, anchor.nextSibling);
    } else {
        container.appendChild(pill);
    }

    let dismissed = false;
    const dismiss = () => {
        if (dismissed) return;
        dismissed = true;
        if (pill.parentNode) pill.parentNode.removeChild(pill);
    };
    return dismiss;
}

/**
 * Show a small floating toast inside the editor when an AI skill fails.
 *
 * We don't take a hard dependency on the host's toast system because the
 * plugin needs to work standalone. The toast auto-dismisses after ~4s and
 * is mounted into ``ctx.container`` so it inherits the editor's stacking
 * context — no overlay collisions with the format bar or slash menu.
 * @private
 */
function showInlineAiError(ctx, skill, err) {
    try {
        const container = ctx.container;
        if (!container || !container.appendChild) return;

        const msg = err && err.message
            ? String(err.message)
            : 'AI request failed.';

        const toast = document.createElement('div');
        toast.className = 'block-ai-error-toast';
        toast.setAttribute('role', 'alert');
        toast.style.cssText = [
            'position:absolute',
            'right:16px',
            'bottom:16px',
            'max-width:340px',
            'padding:10px 14px',
            'background:#B4262F',
            'color:#FFFFFF',
            'border-radius:6px',
            'box-shadow:0 4px 16px rgba(0,0,0,0.2)',
            'font-size:13px',
            'line-height:1.4',
            'z-index:200',
            'opacity:0',
            'transform:translateY(4px)',
            'transition:opacity 140ms ease, transform 140ms ease',
            'pointer-events:auto',
        ].join(';');

        const label = skill && skill.label ? skill.label : (skill && skill.id) || 'AI';
        toast.innerHTML = `
            <div style="font-weight:600;margin-bottom:2px;">${label} failed</div>
            <div style="opacity:0.9;">${msg.replace(/[<>&]/g, (c) => ({'<':'&lt;','>':'&gt;','&':'&amp;'}[c]))}</div>
        `;

        container.appendChild(toast);
        requestAnimationFrame(() => {
            toast.style.opacity = '1';
            toast.style.transform = 'translateY(0)';
        });

        const dismiss = () => {
            if (!toast.parentNode) return;
            toast.style.opacity = '0';
            toast.style.transform = 'translateY(4px)';
            setTimeout(() => { toast.parentNode && toast.parentNode.removeChild(toast); }, 160);
        };
        toast.addEventListener('click', dismiss);
        setTimeout(dismiss, 4000);
    } catch (_) {
        // Toast is best-effort; never let it break the editor.
    }
}

/**
 * Build a popover element listing the given skills.
 * @private
 */
function buildSkillsMenu(skills, onPick) {
    const root = document.createElement('div');
    root.className = 'block-ai-skills-menu';
    root.setAttribute('role', 'menu');
    root.style.cssText = [
        'background:var(--be-bg)',
        'border:1px solid var(--be-border)',
        'border-radius:var(--be-radius)',
        'box-shadow:var(--be-shadow-lg)',
        'padding:6px 0',
        'min-width:240px',
        'max-height:360px',
        'overflow-y:auto',
        'font-size:0.88rem',
    ].join(';');

    const header = document.createElement('div');
    header.textContent = 'AI Skills';
    header.style.cssText = 'padding:4px 14px 8px;font-size:0.7rem;font-weight:600;letter-spacing:0.04em;text-transform:uppercase;color:var(--be-text-muted);';
    root.appendChild(header);

    // Group by `group`
    const groups = new Map();
    const order  = [];
    skills.forEach(s => {
        const g = s.group || '';
        if (!groups.has(g)) { groups.set(g, []); order.push(g); }
        groups.get(g).push(s);
    });

    order.forEach((g, gi) => {
        if (g && gi > 0) {
            const sep = document.createElement('div');
            sep.style.cssText = 'height:1px;background:var(--be-border);margin:4px 0;';
            root.appendChild(sep);
        }
        if (g) {
            const h = document.createElement('div');
            h.textContent = g;
            h.style.cssText = 'padding:4px 14px 2px;font-size:0.66rem;font-weight:600;letter-spacing:0.04em;text-transform:uppercase;color:var(--be-text-muted);';
            root.appendChild(h);
        }
        groups.get(g).forEach(s => {
            const row = document.createElement('div');
            row.className = 'block-ai-skill-item';
            row.setAttribute('role', 'menuitem');
            row.setAttribute('data-skill-id', s.id);
            row.style.cssText = 'display:flex;align-items:center;gap:10px;padding:6px 14px;cursor:pointer;color:var(--be-text);transition:background 0.1s;';
            row.innerHTML = `
                <span style="width:22px;display:inline-flex;justify-content:center;color:var(--be-text-muted);">${s.icon || '\u2756'}</span>
                <span style="flex:1;">${s.label}</span>
                ${s.desc ? `<span style="font-size:0.72rem;color:var(--be-text-muted);">${s.desc}</span>` : ''}
            `;
            row.addEventListener('mouseenter', () => row.style.background = 'var(--be-bg-hover)');
            row.addEventListener('mouseleave', () => row.style.background = '');
            row.addEventListener('click', () => onPick(s));
            root.appendChild(row);
        });
    });

    return root;
}

/**
 * Create the AI Skills plugin.
 *
 * @param {Object} opts
 * @param {Function} opts.askAI — `async ({skill, selection, block, blocks, signal}) => result`
 * @param {Array}    [opts.skills=DEFAULT_SKILLS]
 * @param {Object}   [opts.surfaces] — toggle UI surfaces: {formatBar,slash,blockMenu}
 * @param {string}   [opts.buttonLabel='\u2728']   — Format bar button label (defaults to sparkle)
 * @param {string}   [opts.buttonTitle='Ask AI']
 * @returns {Object} plugin — `{ name, init }`
 */
export function aiSkillsPlugin(opts = {}) {
    const askAI = typeof opts.askAI === 'function' ? opts.askAI : null;
    const skills = Array.isArray(opts.skills) && opts.skills.length ? opts.skills : DEFAULT_SKILLS;
    const surfaces = Object.assign({ formatBar: true, slash: true, blockMenu: true }, opts.surfaces || {});
    const buttonLabel = opts.buttonLabel || '\u2728';
    const buttonTitle = opts.buttonTitle || 'Ask AI';
    // Notion-style "review before commit" UX: when the AI returns a
    // direct mutation (``replace-*``, ``insert-after``), show an inline
    // pill with the proposed text and Accept / Discard buttons instead
    // of mutating the document outright. Hosts that prefer immediate
    // apply (e.g. an LLM that's always in "trusted" mode) can opt out
    // with ``confirmBeforeApply: false``.
    const confirmBeforeApply = opts.confirmBeforeApply !== false;

    return {
        name: 'ai-skills',
        init(ctx) {
            if (!askAI) {
                console.warn('[ai-skills] plugin installed without an askAI() callback; it will do nothing.');
            }

            const unregisterFns = [];

            /** Run a skill end-to-end: capture context, call askAI, apply result. */
            const runSkill = async (skill, { selection, blockId }) => {
                if (!askAI) return;
                const block = blockId ? ctx.getBlock(blockId) : null;
                const blocks = ctx.getBlocks();
                const controller = new AbortController();

                // Pin the "Generating…" pill to the anchor block so the user
                // sees immediate confirmation that their click landed — LLM
                // calls can run 10–60s and the app would otherwise look dead.
                const anchorBlockId = blockId
                    || (selection && (selection.blockId || (selection.blockIds && selection.blockIds[0])))
                    || null;
                const dismissPill = showGeneratingPill(ctx, {
                    blockId: anchorBlockId,
                    controller,
                    label: skill && skill.label ? skill.label : 'Generating',
                });

                ctx.emit('ai:start', { skillId: skill.id, blockId, selection });
                try {
                    const result = await askAI({
                        skill,
                        skillId: skill.id,
                        selection: selection
                            ? {
                                text: selection.text,
                                blockId: selection.blockId,
                                // Forward the full cross-block span so host
                                // callbacks can scope correctly (e.g. map to
                                // ``target_block_ids`` on the server).
                                blockIds: Array.isArray(selection.blockIds) && selection.blockIds.length
                                    ? selection.blockIds
                                    : (selection.blockId ? [selection.blockId] : []),
                                isCrossBlock: !!selection.isCrossBlock,
                            }
                            : null,
                        block: block ? { id: block.id, type: block.type, content: block.content, meta: { ...block.meta } } : null,
                        blocks,
                        signal: controller.signal,
                    });
                    // Dismiss the spinner *before* we decide whether to
                    // gate on confirmation — otherwise the two pills
                    // momentarily stack which looks janky.
                    dismissPill();

                    const needsConfirm = confirmBeforeApply
                        && result
                        && typeof result.mode === 'string'
                        && result.mode !== 'noop'
                        && result.mode !== 'diff'; // ``diff`` mode already emits its own review UI via ``ai:diff``

                    if (needsConfirm) {
                        ctx.emit('ai:proposal', { skillId: skill.id, result, blockId, selection });
                        showProposalPreview(ctx, {
                            blockId: anchorBlockId,
                            label: skill && skill.label ? `${skill.label}` : 'AI suggestion',
                            previewText: resultPreviewText(result),
                            mode: result.mode,
                            onAccept: () => {
                                try {
                                    applyAiResult(ctx, blockId, selection, result);
                                    ctx.emit('ai:accept', { skillId: skill.id, result });
                                    ctx.emit('ai:done', { skillId: skill.id, result });
                                } catch (err) {
                                    console.error(`[ai-skills] apply on accept for "${skill.id}" threw:`, err);
                                    ctx.emit('ai:error', { skillId: skill.id, error: err });
                                    showInlineAiError(ctx, skill, err);
                                }
                            },
                            onDecline: () => {
                                ctx.emit('ai:decline', { skillId: skill.id, result });
                            },
                        });
                    } else {
                        applyAiResult(ctx, blockId, selection, result);
                        ctx.emit('ai:done', { skillId: skill.id, result });
                    }
                } catch (err) {
                    // Stop-button aborts reach us as AbortError — treat that
                    // as a user cancellation, not a hard failure: no toast,
                    // no error event payload for hosts to alarm on.
                    const aborted = err && (err.name === 'AbortError' || controller.signal.aborted);
                    if (aborted) {
                        ctx.emit('ai:cancel', { skillId: skill.id });
                    } else {
                        // User may never look at the console — surface the
                        // failure inline so they know the AI call didn't just
                        // quietly drop their request. Host apps can also
                        // listen to `ai:error` and render a nicer Toast.
                        console.error(`[ai-skills] "${skill.id}" failed:`, err);
                        ctx.emit('ai:error', { skillId: skill.id, error: err });
                        showInlineAiError(ctx, skill, err);
                    }
                    dismissPill();
                } finally {
                    // Double-dismiss is a no-op; this is just the belt-and-
                    // suspenders catch for any early-return path above.
                    dismissPill();
                }
            };

            /** Open the skills popover anchored to a rect or element. */
            const openSkillsMenu = ({ anchor, blockId, selection }) => {
                const menuEl = buildSkillsMenu(skills, (skill) => {
                    overlay.destroy();
                    runSkill(skill, { selection, blockId });
                });
                const overlay = ctx.mountOverlay(menuEl, {
                    anchor,
                    placement: selection ? 'above-selection' : 'bottom-start',
                    offset: 8,
                });
            };

            // ── Surface 1: Format-bar button ──────────────
            if (surfaces.formatBar) {
                unregisterFns.push(ctx.registerFormatButton({
                    id: 'ai:skills',
                    label: buttonLabel,
                    title: buttonTitle,
                    style: 'font-size:14px;',
                    run: (pctx, sel) => {
                        openSkillsMenu({
                            anchor: sel.range ? sel.range.getBoundingClientRect() : null,
                            blockId: sel.blockId,
                            // Pass through the cross-block selection shape
                            // captured by ``onSelectionChange``. Skills that
                            // scope server-side on ``selection_block_id`` get
                            // the primary block; skills that care about the
                            // full span read ``blockIds`` / ``isCrossBlock``.
                            selection: {
                                text: sel.text,
                                blockId: sel.blockId,
                                blockIds: Array.isArray(sel.blockIds) && sel.blockIds.length
                                    ? sel.blockIds
                                    : (sel.blockId ? [sel.blockId] : []),
                                isCrossBlock: !!sel.isCrossBlock,
                                range: sel.range,
                            },
                        });
                    },
                }));
            }

            // ── Surface 2: Slash-menu group "Ask AI" ──────
            if (surfaces.slash) {
                skills.forEach(skill => {
                    unregisterFns.push(ctx.registerSlashCommand({
                        id: `ai:slash:${skill.id}`,
                        group: 'Ask AI',
                        label: skill.label,
                        desc: skill.desc || '',
                        icon: skill.icon || '\u2728',
                        run: (pctx, { blockId }) => runSkill(skill, {
                            selection: null,
                            blockId,
                        }),
                    }));
                });
            }

            // ── Surface 3: Block action menu ───────────────
            if (surfaces.blockMenu) {
                unregisterFns.push(ctx.registerBlockMenuItem({
                    id: 'ai:block-menu-root',
                    group: 'AI',
                    label: 'Ask AI\u2026',
                    icon: '\u2728',
                    desc: 'Skills',
                    run: (pctx, { blockId }) => {
                        const wrapper = ctx.container.querySelector(`[data-block-id="${blockId}"]`);
                        openSkillsMenu({
                            anchor: wrapper,
                            blockId,
                            selection: null,
                        });
                    },
                }));
            }

            // Cleanup: each register* returns an unregister; call them on destroy.
            return () => {
                unregisterFns.forEach(fn => { try { fn(); } catch (_) {} });
            };
        },
    };
}

export default aiSkillsPlugin;
