/**
 * @fileoverview BlockEditor plugin host — per-instance plugin lifecycle,
 *               registries (slash / format-bar / block-menu / keybindings),
 *               event emitter, and overlay mounting helpers.
 *
 *               Everything a plugin can do flows through the `pluginCtx`
 *               surface built by `makePluginCtx()`; the host manages the
 *               underlying state and back-compat with the legacy module-level
 *               `customCommands` / `customBlockTypes` registries in constants.js.
 *
 * @module module/BlockEditor/plugin-host
 */

import razyui from '../../index.js';
import Icons from '../Icons.js';
import { BLOCK_TYPES, customCommands, customBlockTypes } from './constants.js';
import { openBlockMenu } from './events.js';

// ═══════════════════════════════════════════════
// Registry item shapes (documented, not enforced)
// ═══════════════════════════════════════════════
//
// SlashCommand:   { id, group?, label, desc?, icon?, keywords?, type?, meta?, when?, run?, handler? }
//                 - `type` / `meta` for legacy block-conversion items (no `run`)
//                 - `run(pluginCtx, {blockId})` for plugin-driven actions
//                 - `handler` kept for legacy customCommands parity
//
// FormatButton:   { id, label, title?, icon?, style?, isActive?(sel), when?(sel), run?(pluginCtx, selectionInfo), cmd? }
//                 - `cmd` (legacy): executes document.execCommand / toggleInlineCode / insertInlineLink
//                 - `run` (new): receives pluginCtx + selection info; plugin owns behaviour
//
// BlockMenuItem:  { id, group?, label, icon?, desc?, when?(blockId), run(pluginCtx, {blockId}), separator? }
//                 - Items in the drag-handle click menu
//
// Keybinding:     { id, combo, when?(blockId, evt), run(pluginCtx, {blockId, event}) }
//                 - combo syntax: "mod+b", "mod+shift+s", "ctrl+alt+k"; `mod` = ctrl/cmd

/**
 * Create a new plugin host bound to an editor instance.
 *
 * @param {Object} editorCtx — the editor's internal ctx (from index.js #ctx())
 * @returns {Object} host
 */
export function createPluginHost(editorCtx) {
    const slashCommands  = [];
    const formatButtons  = [];
    const blockMenuItems = [];
    const keybindings    = [];
    const overlays       = new Set();
    const emitter        = new EventTarget();
    const plugins        = [];  // { name, destroy? }

    // ── Seed built-in slash commands from BLOCK_TYPES + legacy registries ──
    BLOCK_TYPES.forEach((bt, i) => {
        slashCommands.push({
            id: `builtin:${bt.type}:${i}`,
            group: 'Basic',
            label: bt.label,
            desc: bt.desc || '',
            icon: bt.icon || '\u2756',
            type: bt.type,
            meta: bt.meta || {},
            builtin: true,
        });
    });
    // Legacy customCommands (module-level, see constants.js)
    customCommands.forEach((c, i) => {
        slashCommands.push({
            id: `legacy-cmd:${c.label}:${i}`,
            group: 'Custom',
            label: c.label,
            desc: c.desc || '',
            icon: c.icon || '\u2756',
            type: c.type || c.label.toLowerCase().replace(/\s+/g, '-'),
            meta: c.meta || {},
            handler: c.handler || null,
            legacy: true,
        });
    });
    // ── Seed built-in format bar buttons (B / I / S / code / link) ──
    formatButtons.push(
        { id: 'builtin:bold',          label: 'B',  title: 'Bold',          cmd: 'bold',          style: 'font-weight:700', builtin: true },
        { id: 'builtin:italic',        label: 'I',  title: 'Italic',        cmd: 'italic',        style: 'font-style:italic', builtin: true },
        { id: 'builtin:strikethrough', label: 'S',  title: 'Strikethrough', cmd: 'strikeThrough', style: 'text-decoration:line-through', builtin: true },
        { id: 'builtin:code',          label: '&lt;&gt;', title: 'Code', cmd: 'code', builtin: true },
        {
            id: 'builtin:link',
            label: Icons.svg ? Icons.svg('link', { size: 14, strokeWidth: 1.5 }) : '\uD83D\uDD17',
            title: 'Link',
            cmd: 'link',
            builtin: true,
        },
    );

    // ── "Turn into" submenu builder ──
    // Returns a raw DOM element ready to be mounted by openBlockMenu, plus a
    // click delegate that applies the conversion. Shared between the hover
    // submenu (driven by openBlockMenu) and the click-fallback ``run`` path.
    function buildTurnIntoSubmenu(blockId) {
        const current = editorCtx.blocks.find(x => x.id === blockId);
        const items = (slashCommands || [])
            .filter(c => c && typeof c.type === 'string' && c.type)
            .filter(c => !current
                || c.type !== current.type
                || (c.meta && current.meta && c.meta.level !== current.meta.level))
            .filter(c => (typeof c.when === 'function')
                ? (() => { try { return !!c.when(blockId); } catch (_) { return true; } })()
                : true);

        if (!items.length) return null;

        const menu = razyui.el('div', { className: 'block-handle-menu block-turn-into-submenu' });
        menu.attr('role', 'menu');
        menu.attr('style', [
            'position:absolute',
            'background:var(--be-bg)',
            'border:1px solid var(--be-border)',
            'border-radius:var(--be-radius)',
            'box-shadow:var(--be-shadow-lg)',
            'padding:4px 0',
            'min-width:220px',
            'max-height:360px',
            'overflow-y:auto',
            'z-index:125',
            'font-size:0.875rem',
        ].join(';'));

        const groupOrder = [];
        const byGroup = new Map();
        items.forEach((it) => {
            const g = it.group || 'Basic';
            if (!byGroup.has(g)) { byGroup.set(g, []); groupOrder.push(g); }
            byGroup.get(g).push(it);
        });

        groupOrder.forEach((g, gi) => {
            if (gi > 0 || groupOrder.length > 1) {
                const header = razyui.el('div', { textContent: g });
                header.attr('style', 'padding:6px 12px 2px;font-size:0.68rem;font-weight:600;letter-spacing:0.04em;text-transform:uppercase;color:var(--be-text-muted);');
                menu.append(header);
            }
            byGroup.get(g).forEach((cmd, idx) => {
                const row = razyui.el('div', {
                    className: 'block-handle-menu-item',
                    'data-cmd-index': String(idx),
                    role: 'menuitem',
                });
                row.attr('data-cmd-type', cmd.type);
                if (cmd.meta && typeof cmd.meta === 'object') {
                    try { row.attr('data-cmd-meta', JSON.stringify(cmd.meta)); } catch (_) { /* ignore */ }
                }
                row.attr('style', [
                    'display:flex',
                    'align-items:center',
                    'gap:8px',
                    'padding:6px 12px',
                    'cursor:pointer',
                    'user-select:none',
                    'color:var(--be-text)',
                    'transition:background 0.1s',
                ].join(';'));
                const iconHtml = cmd.icon
                    ? `<span style="width:20px;display:inline-flex;justify-content:center;color:var(--be-text-muted);">${cmd.icon}</span>`
                    : '<span style="width:20px;"></span>';
                const descHtml = cmd.desc
                    ? `<span style="margin-left:auto;font-size:0.72rem;color:var(--be-text-muted);">${cmd.desc}</span>`
                    : '';
                row.html(`${iconHtml}<span style="flex:1;">${cmd.label}</span>${descHtml}`);
                row.on('mouseenter', () => row.css('background', 'var(--be-bg-hover)'));
                row.on('mouseleave', () => row.css('background', ''));
                menu.append(row);
            });
        });

        return {
            el: menu[0],
            // Pick handler: called by the submenu host on click. The host is
            // responsible for tearing down its own overlays afterwards.
            onPick(target) {
                const row = target && target.closest ? target.closest('.block-handle-menu-item') : null;
                if (!row) return false;
                const type = row.getAttribute('data-cmd-type');
                let meta = {};
                const rawMeta = row.getAttribute('data-cmd-meta');
                if (rawMeta) {
                    try { meta = JSON.parse(rawMeta) || {}; } catch (_) { meta = {}; }
                }
                if (!type) return false;
                editorCtx.convertBlock(blockId, type, meta);
                return true;
            },
        };
    }

    // ── Seed built-in block-menu items (Turn into / Duplicate / Delete) ──
    blockMenuItems.push(
        {
            id: 'builtin:turn-into',
            group: 'Actions',
            label: 'Turn into\u2026',
            icon: '\u21BB',
            desc: 'Convert block type',
            // Flag for the menu host: render a chevron, open on hover.
            hasSubmenu: true,
            // Hover-path: host calls this to get the submenu DOM + pick handler.
            submenu: (ctx /* pluginCtx */, { blockId }) => buildTurnIntoSubmenu(blockId),
            // Click/keyboard fallback: same submenu, mounted right-of the anchor.
            run: (ctx /* pluginCtx */, { blockId }) => {
                const built = buildTurnIntoSubmenu(blockId);
                if (!built) return;
                const wrapperRa = editorCtx.blockElements.get(blockId);
                const anchor = wrapperRa && wrapperRa[0] ? wrapperRa[0] : null;
                const overlay = mountOverlay(built.el, {
                    anchor,
                    placement: 'right-start',
                    offset: 6,
                });
                built.el.addEventListener('click', (ev) => {
                    if (built.onPick(ev.target)) overlay.destroy();
                });
            },
        },
        {
            id: 'builtin:duplicate',
            group: 'Actions',
            label: 'Duplicate',
            icon: '\u29C9',
            run: (ctx, { blockId }) => {
                const b = editorCtx.blocks.find(x => x.id === blockId);
                if (!b) return;
                editorCtx.addBlock(b.type, blockId, b.content, { ...b.meta });
            },
        },
        {
            id: 'builtin:delete',
            group: 'Actions',
            label: 'Delete',
            icon: '\u2715',
            run: (ctx, { blockId }) => editorCtx.removeBlock(blockId),
        },
    );

    // ── Seed built-in keybinding: Ctrl+/ opens the block action menu ──
    // Matches Notion's "click the handle or press Ctrl+/" affordance. We
    // anchor the overlay at the drag handle when we can find one so the menu
    // lines up with the gutter; otherwise we fall back to the block wrapper.
    keybindings.push({
        id: 'builtin:open-block-menu',
        combo: 'mod+/',
        _parsed: parseCombo('mod+/'),
        run: (pluginCtx, { blockId }) => {
            if (!blockId) return;
            const wrapperRa = editorCtx.blockElements.get(blockId);
            let anchor = null;
            if (wrapperRa && wrapperRa[0]) {
                anchor = wrapperRa[0].querySelector('.block-handle') || wrapperRa[0];
            }
            openBlockMenu(editorCtx, blockId, anchor);
        },
    });

    // Legacy customBlockTypes
    customBlockTypes.forEach((cfg, type) => {
        const dup = slashCommands.some(c => c.type === type && c.label === cfg.label);
        if (!dup) {
            slashCommands.push({
                id: `legacy-blocktype:${type}`,
                group: 'Custom',
                label: cfg.label || type,
                desc: cfg.desc || 'Custom block',
                icon: cfg.icon || '\u2756',
                type,
                meta: {},
                legacy: true,
            });
        }
    });

    // ── Change subscribers to notify view.js when registries change ──
    const changeSubs = { slash: [], format: [], blockMenu: [] };
    const notify = (bucket) => {
        (changeSubs[bucket] || []).forEach(fn => {
            try { fn(); } catch (e) { console.error('[BlockEditor plugins] notify error:', e); }
        });
    };

    // ═══════════════════════════════════════════
    // Registration helpers (return unregister fn)
    // ═══════════════════════════════════════════

    const stableId = (prefix, id) => id || `${prefix}:${razyui.hash(6)}`;

    function registerSlashCommand(cfg) {
        if (!cfg || !cfg.label) return () => {};
        const item = { ...cfg, id: stableId('slash', cfg.id) };
        slashCommands.push(item);
        notify('slash');
        return () => {
            const i = slashCommands.indexOf(item);
            if (i >= 0) { slashCommands.splice(i, 1); notify('slash'); }
        };
    }

    function registerFormatButton(cfg) {
        if (!cfg || (!cfg.label && !cfg.icon)) return () => {};
        const item = { ...cfg, id: stableId('format', cfg.id) };
        formatButtons.push(item);
        notify('format');
        return () => {
            const i = formatButtons.indexOf(item);
            if (i >= 0) { formatButtons.splice(i, 1); notify('format'); }
        };
    }

    function registerBlockMenuItem(cfg) {
        if (!cfg || (!cfg.label && !cfg.separator)) return () => {};
        const item = { ...cfg, id: stableId('blockmenu', cfg.id) };
        blockMenuItems.push(item);
        notify('blockMenu');
        return () => {
            const i = blockMenuItems.indexOf(item);
            if (i >= 0) { blockMenuItems.splice(i, 1); notify('blockMenu'); }
        };
    }

    function registerKeybinding(cfg) {
        if (!cfg || !cfg.combo || typeof cfg.run !== 'function') return () => {};
        const item = { ...cfg, id: stableId('key', cfg.id), _parsed: parseCombo(cfg.combo) };
        keybindings.push(item);
        return () => {
            const i = keybindings.indexOf(item);
            if (i >= 0) keybindings.splice(i, 1);
        };
    }

    function parseCombo(combo) {
        const parts = String(combo).toLowerCase().split('+').map(s => s.trim()).filter(Boolean);
        const out = { mod: false, ctrl: false, shift: false, alt: false, meta: false, key: '' };
        for (const p of parts) {
            if (p === 'mod')   out.mod = true;
            else if (p === 'ctrl')  out.ctrl = true;
            else if (p === 'shift') out.shift = true;
            else if (p === 'alt')   out.alt = true;
            else if (p === 'cmd' || p === 'meta') out.meta = true;
            else out.key = p;
        }
        return out;
    }

    /**
     * Test whether a keyboard event matches a parsed combo.
     * @returns {boolean}
     */
    function matchCombo(parsed, e) {
        if (!parsed.key) return false;
        if (e.key.toLowerCase() !== parsed.key) return false;
        const mod = e.ctrlKey || e.metaKey;
        if (parsed.mod   && !mod) return false;
        if (parsed.ctrl  && !e.ctrlKey) return false;
        if (parsed.meta  && !e.metaKey) return false;
        if (parsed.shift && !e.shiftKey) return false;
        if (parsed.alt   && !e.altKey) return false;
        // Disallow stray modifiers only when none were requested
        if (!parsed.mod && !parsed.ctrl && !parsed.meta && (e.ctrlKey || e.metaKey)) return false;
        if (!parsed.shift && e.shiftKey && parsed.key.length === 1) return false;
        if (!parsed.alt && e.altKey) return false;
        return true;
    }

    /**
     * Dispatch a keydown against registered bindings.
     * @returns {boolean} true if a binding handled the event
     */
    function handleKeydown(e, blockId) {
        for (const kb of keybindings) {
            if (!matchCombo(kb._parsed, e)) continue;
            if (typeof kb.when === 'function' && !kb.when(blockId, e)) continue;
            try {
                kb.run(makePluginCtx({ owner: kb.id }), { blockId, event: e });
                return true;
            } catch (err) {
                console.error(`[BlockEditor plugins] keybinding "${kb.id}" threw:`, err);
            }
        }
        return false;
    }

    // ═══════════════════════════════════════════
    // Change subscription (used by view.js to rebuild menus)
    // ═══════════════════════════════════════════
    function onRegistryChange(bucket, fn) {
        if (!changeSubs[bucket]) return () => {};
        changeSubs[bucket].push(fn);
        return () => {
            const i = changeSubs[bucket].indexOf(fn);
            if (i >= 0) changeSubs[bucket].splice(i, 1);
        };
    }

    // ═══════════════════════════════════════════
    // Events
    // ═══════════════════════════════════════════
    function on(event, cb)   { emitter.addEventListener(event, cb); return () => emitter.removeEventListener(event, cb); }
    function off(event, cb)  { emitter.removeEventListener(event, cb); }
    function emit(event, detail) { emitter.dispatchEvent(new CustomEvent(event, { detail })); }

    // ═══════════════════════════════════════════
    // Overlay management — floating UI helper
    // ═══════════════════════════════════════════

    /**
     * Mount a floating overlay element inside the editor container.
     *
     * @param {HTMLElement} el — the overlay element (raw DOM, no wrapper)
     * @param {Object} [opts]
     * @param {HTMLElement|DOMRect|{top,left}} [opts.anchor] — element or rect to anchor near
     * @param {'bottom-start'|'top-start'|'right-start'|'above-selection'} [opts.placement='bottom-start']
     * @param {number} [opts.offset=4] — gap in px
     * @param {boolean} [opts.closeOnOutsideClick=true]
     * @param {boolean} [opts.closeOnEscape=true]
     * @param {Function} [opts.onClose]
     * @returns {{ el: HTMLElement, destroy: Function, reposition: Function }}
     */
    function mountOverlay(el, opts = {}) {
        const placement = opts.placement || 'bottom-start';
        const offset    = typeof opts.offset === 'number' ? opts.offset : 4;
        const container = editorCtx.container[0];

        el.style.position = 'absolute';
        el.style.zIndex   = el.style.zIndex || '120';
        container.appendChild(el);

        const reposition = () => {
            let rect;
            if (opts.anchor instanceof Element) rect = opts.anchor.getBoundingClientRect();
            else if (opts.anchor && 'top' in opts.anchor) rect = opts.anchor;
            else {
                const sel = window.getSelection();
                if (sel && sel.rangeCount) rect = sel.getRangeAt(0).getBoundingClientRect();
            }
            if (!rect) return;
            const cRect = container.getBoundingClientRect();

            let top = 0, left = 0;
            if (placement === 'bottom-start') {
                top  = rect.bottom - cRect.top + offset;
                left = rect.left - cRect.left;
            } else if (placement === 'top-start') {
                top  = rect.top - cRect.top - el.offsetHeight - offset;
                left = rect.left - cRect.left;
            } else if (placement === 'right-start') {
                top  = rect.top - cRect.top;
                left = rect.right - cRect.left + offset;
            } else if (placement === 'above-selection') {
                top  = rect.top - cRect.top - el.offsetHeight - offset;
                left = rect.left - cRect.left + rect.width / 2 - el.offsetWidth / 2;
            }
            el.style.top  = `${Math.max(0, top)}px`;
            el.style.left = `${Math.max(0, left)}px`;
        };
        reposition();

        const handle = { el, reposition, destroy: null };

        const onDocDown = (ev) => {
            if (!el.contains(ev.target)) destroy();
        };
        const onKey = (ev) => {
            if (ev.key === 'Escape') destroy();
        };
        const destroy = () => {
            if (handle._destroyed) return;
            handle._destroyed = true;
            if (opts.closeOnOutsideClick !== false) document.removeEventListener('mousedown', onDocDown, true);
            if (opts.closeOnEscape       !== false) document.removeEventListener('keydown',   onKey,    true);
            try { el.remove(); } catch (_) { /* noop */ }
            overlays.delete(handle);
            if (typeof opts.onClose === 'function') opts.onClose();
        };
        handle.destroy = destroy;
        overlays.add(handle);

        // Defer outside-click binding so the current click doesn't immediately close
        if (opts.closeOnOutsideClick !== false) {
            setTimeout(() => document.addEventListener('mousedown', onDocDown, true), 0);
        }
        if (opts.closeOnEscape !== false) {
            document.addEventListener('keydown', onKey, true);
        }
        return handle;
    }

    function closeAllOverlays() {
        [...overlays].forEach(o => { try { o.destroy(); } catch (_) {} });
        overlays.clear();
    }

    // ═══════════════════════════════════════════
    // Public plugin context (given to each plugin)
    // ═══════════════════════════════════════════

    /**
     * Build the `pluginCtx` passed to `plugin.init(ctx)`.
     *
     * @param {Object} [meta]
     * @param {string} [meta.owner] — plugin name/id (for diagnostics)
     */
    function makePluginCtx(meta = {}) {
        // NOTE: control is resolved lazily. Calling
        // ``editorCtx.editorInstance.getControl()`` during the editor's
        // own constructor (which happens when a plugin is passed via the
        // ``plugins: [...]`` config option) triggered a cross-class
        // private-field access in minified builds — the razyui core
        // wrapper's ``getControl`` isn't safe to call until the outer
        // constructor completes. Plugins almost never need ``ctx.editor``
        // synchronously during ``init``, so deferring is safe.
        let _control = null;
        const getControl = () => {
            if (!_control) {
                try { _control = editorCtx.editorInstance.getControl(); }
                catch (e) { _control = null; }
            }
            return _control;
        };
        // Primitive block-data helpers that don't need the public control
        // surface — they go straight to the editor's internal state.
        const snapshotBlocks = () => editorCtx.blocks.map(b => ({
            id: b.id, type: b.type, content: b.content, meta: { ...(b.meta || {}) },
        }));
        const replaceBlocks = (next) => {
            // Clear in-place using the editorCtx primitives so block
            // elements unmount cleanly, then append the new set.
            const existing = [...editorCtx.blocks];
            existing.forEach(b => editorCtx.removeBlock(b.id));
            (Array.isArray(next) ? next : []).forEach(b => {
                editorCtx.addBlock(
                    String(b.type || 'paragraph'),
                    null,
                    String(b.content || ''),
                    (b.meta && typeof b.meta === 'object') ? b.meta : {},
                );
            });
            if (!editorCtx.blocks.length) editorCtx.addBlock('paragraph');
        };

        return {
            /** Plugin-scoped logging tag */
            owner: meta.owner || 'plugin',

            /** Raw editor control (getBlocks/setBlocks/focus/etc.) — lazy. */
            get editor() { return getControl(); },

            /** Editor root element */
            get container() { return editorCtx.container[0]; },

            /** razyui module reference */
            get razyui() { return razyui; },

            // ── Data helpers ─────────────────────
            getBlocks: snapshotBlocks,
            setBlocks: replaceBlocks,
            getBlock:  (id) => editorCtx.blocks.find(b => b.id === id) || null,
            addBlock:    (type, afterId, content, meta2) => editorCtx.addBlock(type, afterId, content, meta2),
            removeBlock: (id) => editorCtx.removeBlock(id),
            moveBlock:   (id, toIdx) => editorCtx.moveBlock(id, toIdx),
            convertBlock:(id, type, meta2) => editorCtx.convertBlock(id, type, meta2),
            focusBlock:  (id, pos) => editorCtx.focusBlock(id, pos),
            updateBlock: (id, patch) => {
                const b = editorCtx.blocks.find(x => x.id === id);
                if (!b) return;
                if (patch && typeof patch.content === 'string') b.content = patch.content;
                if (patch && patch.meta && typeof patch.meta === 'object') Object.assign(b.meta, patch.meta);
                if (patch && (patch.content !== undefined || patch.meta)) {
                    editorCtx.rerenderBlockContent(id);
                    editorCtx.fireChange();
                }
            },

            // ── Selection ────────────────────────
            /**
             * Block id closest to the current selection/focus inside the editor.
             */
            getActiveBlockId: () => {
                const root = editorCtx.contentEl[0];
                const active = document.activeElement;
                if (active && root.contains(active)) {
                    const w = active.closest('[data-block-id]');
                    if (w) return w.dataset.blockId;
                }
                const sel = window.getSelection();
                if (sel && sel.rangeCount) {
                    const a = sel.anchorNode;
                    if (a && root.contains(a)) {
                        const node = a.nodeType === Node.ELEMENT_NODE ? a : a.parentElement;
                        const w = node && node.closest && node.closest('[data-block-id]');
                        if (w) return w.dataset.blockId;
                    }
                }
                return null;
            },

            /**
             * Current non-collapsed selection inside the editor, or null.
             * @returns {null | { text: string, blockId: string, rect: DOMRect, range: Range }}
             */
            getSelection: () => {
                const sel = window.getSelection();
                if (!sel || sel.rangeCount === 0 || sel.isCollapsed) return null;
                const root = editorCtx.contentEl[0];
                const range = sel.getRangeAt(0);
                if (!root.contains(range.commonAncestorContainer)) return null;
                const anchor = sel.anchorNode;
                const node = anchor?.nodeType === Node.ELEMENT_NODE ? anchor : anchor?.parentElement;
                const w = node && node.closest && node.closest('[data-block-id]');
                return {
                    text: sel.toString(),
                    blockId: w ? w.dataset.blockId : null,
                    rect: range.getBoundingClientRect(),
                    range,
                };
            },

            // ── Registrations (all return unregister fn) ─────
            registerSlashCommand,
            registerFormatButton,
            registerBlockMenuItem,
            registerKeybinding,
            /** Scoped block-type registration that also honours the global legacy path. */
            registerBlockType: (cfg) => {
                // Delegate to module-level registry so view.js's default render path sees it.
                if (!cfg || !cfg.type) return () => {};
                customBlockTypes.set(cfg.type, cfg);
                // Also expose in slash menu via a slash command
                const unreg = registerSlashCommand({
                    id: `blocktype:${cfg.type}`,
                    group: cfg.group || 'Custom',
                    label: cfg.label || cfg.type,
                    desc: cfg.desc || 'Custom block',
                    icon: cfg.icon || '\u2756',
                    type: cfg.type,
                    meta: cfg.meta || {},
                });
                return () => { unreg(); customBlockTypes.delete(cfg.type); };
            },

            // ── Events ───────────────────────────
            on, off, emit,

            // ── Overlays ─────────────────────────
            mountOverlay,
            closeAllOverlays,
        };
    }

    // ═══════════════════════════════════════════
    // Plugin lifecycle
    // ═══════════════════════════════════════════

    /**
     * Install a plugin instance.
     * Accepts either a function `(pluginCtx) => destroy?` or an object
     * `{ name, init(pluginCtx), destroy? }`.
     * @returns {Function} disposer — calls the plugin's destroy() and
     *                    removes it from the active list.
     */
    function installPlugin(plugin) {
        if (!plugin) return () => {};
        let name = 'anonymous-plugin';
        let initFn = null;
        let destroyFn = null;

        if (typeof plugin === 'function') {
            initFn = plugin;
            name   = plugin.name || name;
        } else if (typeof plugin === 'object') {
            name = plugin.name || name;
            if (typeof plugin.init === 'function') initFn = plugin.init;
            if (typeof plugin.destroy === 'function') destroyFn = plugin.destroy;
        }
        if (!initFn && !destroyFn) return () => {};

        const ctx = makePluginCtx({ owner: name });
        let ret;
        try {
            ret = initFn ? initFn(ctx) : undefined;
        } catch (e) {
            console.error(`[BlockEditor plugins] "${name}" init threw:`, e);
            return () => {};
        }

        if (typeof ret === 'function') destroyFn = ret;
        else if (ret && typeof ret.destroy === 'function') destroyFn = ret.destroy;

        const entry = { name, destroy: destroyFn };
        plugins.push(entry);
        return () => {
            const i = plugins.indexOf(entry);
            if (i >= 0) plugins.splice(i, 1);
            if (typeof destroyFn === 'function') {
                try { destroyFn(); }
                catch (e) { console.error(`[BlockEditor plugins] "${name}" destroy threw:`, e); }
            }
        };
    }

    function destroy() {
        for (const p of plugins) {
            if (typeof p.destroy === 'function') {
                try { p.destroy(); }
                catch (e) { console.error(`[BlockEditor plugins] "${p.name}" destroy threw:`, e); }
            }
        }
        plugins.length = 0;
        closeAllOverlays();
        slashCommands.length  = 0;
        formatButtons.length  = 0;
        blockMenuItems.length = 0;
        keybindings.length    = 0;
    }

    return {
        // Registries (read-only from view.js perspective, mutated via register* fns)
        slashCommands,
        formatButtons,
        blockMenuItems,
        keybindings,

        // Lifecycle
        installPlugin,
        destroy,

        // Events
        on, off, emit,

        // Key dispatch
        handleKeydown,

        // Change subscription
        onRegistryChange,

        // Overlays / helpers
        mountOverlay,
        closeAllOverlays,
        makePluginCtx,
    };
}
