/**
 * @fileoverview BlockEditor virtualizer — viewport-based mount/unmount of
 *               block contents so very long documents stay smooth.
 *
 * Strategy ("materialize on enter, demote on leave"):
 *
 *   • An IntersectionObserver watches every block wrapper.
 *   • When a wrapper enters the (extended) viewport, its `.block-content`
 *     is rendered for real via `renderBlockContent()`.
 *   • When a wrapper leaves the viewport (and stays out for a brief
 *     hysteresis window), its `.block-content` is replaced by an empty
 *     placeholder div whose `min-height` matches the last measured
 *     real-content height — so scroll position never jumps.
 *
 * Properties:
 *
 *   • Block *data* (`block.content`, `block.meta`) is the source of truth
 *     and never lost. The DOM `.block-content` is recreated from data on
 *     materialize, the same way `convertBlock` already does.
 *   • Markdown export (`#exportMarkdown`) reads from data, not DOM, so
 *     virtualized blocks export correctly.
 *   • Editing (`bindEditableEvents` `input` listeners) keeps `block.content`
 *     in sync as the user types, so demoting the same block later loses
 *     nothing.
 *   • The currently focused / editing block is never demoted.
 *   • Drag handles & "+" buttons live in `.block-controls`, which stays in
 *     the DOM regardless of materialization, so reorder UI keeps working.
 *   • `regular`-type blocks (lite MarkdownEditor) and custom block types
 *     get their `destroy` / `onDestroy` hooks called on demotion, and a
 *     fresh instance is created on rematerialize.
 *
 * Threshold:
 *   The virtualizer is only "active" once `editorCtx.blocks.length`
 *   reaches `opts.minBlocks` (default 50). Below that, all blocks are
 *   materialized and no demotion ever runs — small docs behave exactly
 *   like before.
 *
 * @module module/BlockEditor/virtualizer
 */

import razyui from '../../index.js';
import { customBlockTypes } from './constants.js';
import { renderBlockContent } from './view.js';

/**
 * @typedef {Object} VirtualizerOptions
 * @property {boolean} [enabled=true]
 * @property {number}  [minBlocks=50]      — only virtualize once doc has ≥ N blocks
 * @property {string}  [rootMargin='800px 0px'] — IntersectionObserver rootMargin
 * @property {number}  [demoteDelayMs=400] — wait this long after exit before demoting
 * @property {number}  [defaultPlaceholderPx=28] — initial min-height before measuring
 */

/**
 * Create a virtualizer instance bound to one BlockEditor.
 * @param {Object} editorCtx — the same context object used by view.js
 * @param {VirtualizerOptions} [opts]
 */
export function createVirtualizer(editorCtx, opts = {}) {
    const config = {
        enabled:              opts.enabled !== false,
        minBlocks:            Number.isFinite(opts.minBlocks) ? opts.minBlocks : 50,
        rootMargin:           opts.rootMargin || '800px 0px',
        demoteDelayMs:        Number.isFinite(opts.demoteDelayMs) ? opts.demoteDelayMs : 400,
        defaultPlaceholderPx: Number.isFinite(opts.defaultPlaceholderPx) ? opts.defaultPlaceholderPx : 28,
    };

    /** Last measured `.block-content` height (px) per block id. */
    const heights = new Map();
    /** Block ids whose content is currently mounted (real, not placeholder). */
    const materialized = new Set();
    /** Pending demote timers, keyed by block id. */
    const pendingDemote = new Map();
    /** Wrappers currently observed. Used to safely unobserve on destroy. */
    const observed = new Set();

    let observer = null;
    let destroyed = false;

    function isActive() {
        return config.enabled && editorCtx.blocks.length >= config.minBlocks;
    }

    function getWrapperEl(wrapper) {
        if (!wrapper) return null;
        return wrapper && wrapper[0] ? wrapper[0] : wrapper;
    }

    function findContentEl(wrapperEl) {
        if (!wrapperEl) return null;
        // Direct child .block-content (defensive against nested matches).
        for (const child of wrapperEl.children) {
            if (child.classList && child.classList.contains('block-content')) return child;
        }
        return wrapperEl.querySelector(':scope > .block-content');
    }

    function isFocusedBlock(id) {
        const root = editorCtx.contentEl && editorCtx.contentEl[0];
        const active = document.activeElement;
        if (!root || !active || !root.contains(active)) return false;
        const w = active.closest('[data-block-id]');
        return !!(w && w.dataset.blockId === id);
    }

    function recordHeight(id) {
        const wrapper = editorCtx.blockElements.get(id);
        const el = findContentEl(getWrapperEl(wrapper));
        if (!el) return;
        const h = el.getBoundingClientRect().height;
        if (h > 0) heights.set(id, h);
    }

    function makePlaceholder(id) {
        const h = heights.get(id) || config.defaultPlaceholderPx;
        const ph = razyui.el('div', {
            className: 'block-content',
            'data-virtualized': 'true',
            'aria-hidden': 'true',
            style: `min-height:${h}px;`,
        });
        // Mark for fast lookup.
        ph.attr('data-block-content-id', id);
        return ph;
    }

    /**
     * Materialize a block — replace placeholder (if any) with real content.
     */
    function materialize(id) {
        if (destroyed) return;
        if (materialized.has(id)) return;
        cancelPendingDemote(id);

        const block = editorCtx.blocks.find(b => b.id === id);
        if (!block) return;
        const wrapper = editorCtx.blockElements.get(id);
        const wrapperEl = getWrapperEl(wrapper);
        if (!wrapperEl) return;

        const oldContent = findContentEl(wrapperEl);
        const fresh = renderBlockContent(editorCtx, block); // razyui-wrapped element
        const freshEl = fresh && fresh[0] ? fresh[0] : fresh;

        if (oldContent) oldContent.replaceWith(freshEl);
        else wrapperEl.appendChild(freshEl);

        materialized.add(id);

        // Measure the real height once it lays out — used for future placeholder.
        requestAnimationFrame(() => recordHeight(id));
    }

    /**
     * Demote a block — replace its real content with a height-preserving
     * placeholder. Refuses to demote the currently focused/editing block.
     */
    function demote(id) {
        if (destroyed) return;
        if (!materialized.has(id)) return;
        if (isFocusedBlock(id)) return;

        const block = editorCtx.blocks.find(b => b.id === id);
        const wrapper = editorCtx.blockElements.get(id);
        const wrapperEl = getWrapperEl(wrapper);
        if (!block || !wrapperEl) return;

        // Always remember the latest height before swapping out.
        recordHeight(id);

        // Tear down lite-MarkdownEditor instance if any (it'll be re-created
        // by `renderBlockContent` next time).
        const lite = editorCtx.liteEditors && editorCtx.liteEditors.get
            ? editorCtx.liteEditors.get(id)
            : null;
        if (lite) {
            try { lite.destroy(); } catch (_) { /* ignore */ }
            editorCtx.liteEditors.delete(id);
        }
        // Custom block-type cleanup hook.
        const customType = customBlockTypes.get(block.type);
        if (customType && typeof customType.onDestroy === 'function') {
            try { customType.onDestroy(block); } catch (_) { /* ignore */ }
        }

        const oldContent = findContentEl(wrapperEl);
        const placeholder = makePlaceholder(id);
        const phEl = placeholder[0] ? placeholder[0] : placeholder;
        if (oldContent) oldContent.replaceWith(phEl);
        else wrapperEl.appendChild(phEl);

        materialized.delete(id);
    }

    function cancelPendingDemote(id) {
        const t = pendingDemote.get(id);
        if (t) { clearTimeout(t); pendingDemote.delete(id); }
    }

    function scheduleDemote(id) {
        if (!isActive()) return;
        if (isFocusedBlock(id)) return;
        cancelPendingDemote(id);
        const t = setTimeout(() => {
            pendingDemote.delete(id);
            // Re-check: still off-screen? still not focused?
            const wrapper = editorCtx.blockElements.get(id);
            const el = getWrapperEl(wrapper);
            if (!el || isFocusedBlock(id)) return;
            const rect = el.getBoundingClientRect();
            const margin = 800;
            const inExtended = rect.bottom > -margin
                && rect.top < (window.innerHeight || document.documentElement.clientHeight) + margin;
            if (!inExtended) demote(id);
        }, config.demoteDelayMs);
        pendingDemote.set(id, t);
    }

    /**
     * Public: ensure a block is materialized right now (sync). Used before
     * `focus`, `getEditableInBlock`, scroll-into-view, etc.
     */
    function ensureMaterialized(id) {
        if (!id) return;
        materialize(id);
    }

    /**
     * Public: render a freshly-added wrapper *initially* as a placeholder.
     * Called by index.js during bulk loads (`#init` → cfg.blocks /
     * importMarkdown) to skip rendering thousands of editables eagerly.
     */
    function renderInitialPlaceholder(wrapper, blockId) {
        const wrapperEl = getWrapperEl(wrapper);
        if (!wrapperEl) return;
        const oldContent = findContentEl(wrapperEl);
        const placeholder = makePlaceholder(blockId);
        const phEl = placeholder[0] ? placeholder[0] : placeholder;
        if (oldContent) oldContent.replaceWith(phEl);
        else wrapperEl.appendChild(phEl);
        materialized.delete(blockId);
    }

    /**
     * Public: should `#addBlock` initially place a placeholder instead of
     * the rendered content? True only when virtualization is active AND the
     * caller signals this is part of a bulk load.
     *
     * @param {{ bulk?: boolean }} [meta]
     */
    function shouldDeferInitial(meta) {
        if (!isActive()) return false;
        return !!(meta && meta.bulk);
    }

    function ensureObserver() {
        if (observer) return observer;
        if (typeof IntersectionObserver === 'undefined') return null;
        observer = new IntersectionObserver((entries) => {
            for (const entry of entries) {
                const id = entry.target.dataset && entry.target.dataset.blockId;
                if (!id) continue;
                if (entry.isIntersecting) {
                    cancelPendingDemote(id);
                    materialize(id);
                } else {
                    scheduleDemote(id);
                }
            }
        }, { rootMargin: config.rootMargin });
        return observer;
    }

    function observeWrapper(wrapper) {
        const el = getWrapperEl(wrapper);
        if (!el) return;
        const ob = ensureObserver();
        if (!ob) return;
        if (observed.has(el)) return;
        ob.observe(el);
        observed.add(el);
    }

    function unobserveWrapper(wrapper) {
        const el = getWrapperEl(wrapper);
        if (!el) return;
        if (observer && observed.has(el)) observer.unobserve(el);
        observed.delete(el);
        if (el.dataset && el.dataset.blockId) {
            cancelPendingDemote(el.dataset.blockId);
            materialized.delete(el.dataset.blockId);
            heights.delete(el.dataset.blockId);
        }
    }

    /**
     * Activate / refresh observation. Called once after the editor's
     * initial blocks are mounted. Idempotent — safe to call again after
     * bulk inserts.
     */
    function attach() {
        if (destroyed) return;
        ensureObserver();
        // Pick up any wrappers that were inserted before `attach()` (or
        // before observer existed).
        editorCtx.blockElements.forEach((wrapper) => observeWrapper(wrapper));
    }

    function destroy() {
        destroyed = true;
        for (const t of pendingDemote.values()) clearTimeout(t);
        pendingDemote.clear();
        if (observer) {
            try { observer.disconnect(); } catch (_) { /* ignore */ }
        }
        observer = null;
        observed.clear();
        materialized.clear();
        heights.clear();
    }

    return {
        // Lifecycle
        attach,
        destroy,
        // Wrapper lifecycle
        observeWrapper,
        unobserveWrapper,
        // Materialization
        materialize,
        demote,
        ensureMaterialized,
        renderInitialPlaceholder,
        shouldDeferInitial,
        // Introspection
        isActive,
        recordHeight,
        get materializedCount() { return materialized.size; },
        get observedCount() { return observed.size; },
        get config() { return { ...config }; },
    };
}
